using ArtForgeAI.Models;
using Microsoft.EntityFrameworkCore;

namespace ArtForgeAI.Data;

public class AppDbContext : DbContext
{
    public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

    public DbSet<ImageGeneration> ImageGenerations => Set<ImageGeneration>();
    public DbSet<UserPreference> UserPreferences => Set<UserPreference>();
    public DbSet<ImageSizeMaster> ImageSizeMasters => Set<ImageSizeMaster>();
    public DbSet<StylePreset> StylePresets => Set<StylePreset>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<ImageGeneration>(entity =>
        {
            entity.HasIndex(e => e.UserId);
            entity.HasIndex(e => e.CreatedAt);
        });

        modelBuilder.Entity<UserPreference>(entity =>
        {
            entity.HasIndex(e => e.UserId).IsUnique();
        });

        modelBuilder.Entity<ImageSizeMaster>().HasData(
            new ImageSizeMaster { Id = 1, Name = "Square", Width = 1024, Height = 1024, IsActive = true, SortOrder = 1, Unit = "px", DisplayWidth = 1024, DisplayHeight = 1024 },
            new ImageSizeMaster { Id = 2, Name = "Landscape", Width = 1792, Height = 1024, IsActive = true, SortOrder = 2, Unit = "px", DisplayWidth = 1792, DisplayHeight = 1024 },
            new ImageSizeMaster { Id = 3, Name = "Portrait", Width = 1024, Height = 1792, IsActive = true, SortOrder = 3, Unit = "px", DisplayWidth = 1024, DisplayHeight = 1792 }
        );

        // ── Style Presets seed data (25 styles) ──
        modelBuilder.Entity<StylePreset>().HasData(
            // Artistic (8)
            new StylePreset { Id = 1, Name = "Anime", Description = "Japanese anime illustration style", PromptTemplate = "Transform into high-quality anime illustration style. Clean cel-shaded coloring with soft gradients. Large expressive eyes. Fine detailed linework. Vibrant colors. Lush painted background. Professional anime production quality, Studio Ghibli inspired.", Category = "Artistic", IconEmoji = "\U0001F38C", AccentColor = "#E91E63", IsActive = true, SortOrder = 1 },
            new StylePreset { Id = 2, Name = "Manga", Description = "Black & white Japanese manga", PromptTemplate = "Transform into Japanese manga style. Clean precise ink linework. Screentone shading. Expressive eyes and dynamic poses. Black and white with dramatic contrast. Professional manga quality.", Category = "Artistic", IconEmoji = "\U0001F4D6", AccentColor = "#263238", IsActive = true, SortOrder = 2 },
            new StylePreset { Id = 3, Name = "Oil Painting", Description = "Classical oil painting on canvas", PromptTemplate = "Transform into a classical oil painting. Rich impasto brushstrokes, visible canvas texture. Deep saturated colors with luminous glazing technique. Dramatic chiaroscuro lighting. Museum-quality fine art.", Category = "Artistic", IconEmoji = "\U0001F5BC\uFE0F", AccentColor = "#8D6E63", IsActive = true, SortOrder = 3 },
            new StylePreset { Id = 4, Name = "Watercolor", Description = "Delicate watercolor painting", PromptTemplate = "Transform into a delicate watercolor painting. Soft translucent washes of color. Wet-on-wet bleeding edges. Visible paper grain. Light ethereal quality with gentle color transitions. Professional illustration.", Category = "Artistic", IconEmoji = "\U0001F3A8", AccentColor = "#42A5F5", IsActive = true, SortOrder = 4 },
            new StylePreset { Id = 5, Name = "Charcoal", Description = "Expressive charcoal drawing", PromptTemplate = "Transform into an expressive charcoal drawing. Rich dark values, dramatic contrast. Smudged soft edges with sharp accents. Textured paper grain visible. Raw, emotional artistic quality.", Category = "Artistic", IconEmoji = "\U0001F5A4", AccentColor = "#37474F", IsActive = true, SortOrder = 5 },
            new StylePreset { Id = 6, Name = "Impressionist", Description = "Monet/Renoir painting style", PromptTemplate = "Transform into an Impressionist painting in the style of Monet and Renoir. Loose visible brushstrokes capturing light and movement. Vibrant dappled colors, soft focus on forms. Emphasis on natural light, atmospheric effects, and fleeting moments. En plein air quality with warm luminous palette.", Category = "Artistic", IconEmoji = "\U0001F33B", AccentColor = "#7E57C2", IsActive = true, SortOrder = 6 },
            new StylePreset { Id = 7, Name = "Vintage/Retro", Description = "Faded retro photograph look", PromptTemplate = "Transform into a vintage retro photograph style. Faded warm color tones with slight sepia wash. Visible film grain and subtle light leaks. Soft vignetting around edges. Nostalgic 1970s Kodachrome aesthetic. Slightly desaturated with warm amber highlights and muted shadows.", Category = "Artistic", IconEmoji = "\U0001F4F7", AccentColor = "#FF8F00", IsActive = true, SortOrder = 7 },
            new StylePreset { Id = 8, Name = "Flower Petals", Description = "Portrait made of flower petals", PromptTemplate = "Transform into a stunning portrait composed entirely of flower petals and botanical elements. The subject's features are recreated using carefully arranged rose petals, cherry blossoms, lavender, and wildflowers. Delicate floral textures form the hair, skin, and clothing. Surrounded by floating petals and soft natural light. Ethereal, romantic botanical art quality.", Category = "Artistic", IconEmoji = "\U0001F338", AccentColor = "#F06292", IsActive = true, SortOrder = 8 },

            // Fun (7)
            new StylePreset { Id = 9, Name = "Cartoon", Description = "Vibrant cartoon illustration", PromptTemplate = "Transform into vibrant cartoon illustration style. Bold outlines, flat vibrant colors, exaggerated proportions. Playful and dynamic. Clean vector-like rendering. Professional animation quality.", Category = "Fun", IconEmoji = "\U0001F3AA", AccentColor = "#FF5722", IsActive = true, SortOrder = 9 },
            new StylePreset { Id = 10, Name = "Pop Art", Description = "Bold Warhol-style pop art", PromptTemplate = "Transform into bold pop art style. Bright saturated primary colors, halftone dot patterns, thick black outlines. Andy Warhol / Roy Lichtenstein inspired. High contrast, graphic, iconic.", Category = "Fun", IconEmoji = "\U0001F4A5", AccentColor = "#F44336", IsActive = true, SortOrder = 10 },
            new StylePreset { Id = 11, Name = "Pixel Art", Description = "Retro 16-bit pixel style", PromptTemplate = "Transform into retro pixel art style. Clean pixel grid, limited color palette, 16-bit aesthetic. Sharp pixels, no anti-aliasing. Nostalgic video game art quality.", Category = "Fun", IconEmoji = "\U0001F579\uFE0F", AccentColor = "#4CAF50", IsActive = true, SortOrder = 11 },
            new StylePreset { Id = 12, Name = "Comic", Description = "Comic book illustration", PromptTemplate = "Transform into comic book illustration. Bold ink outlines, dynamic shading with halftone dots. Vibrant flat colors. Action-pose energy. Professional Marvel/DC quality linework.", Category = "Fun", IconEmoji = "\U0001F4AC", AccentColor = "#2196F3", IsActive = true, SortOrder = 12 },
            new StylePreset { Id = 13, Name = "Clay/Claymation", Description = "Charming claymation style", PromptTemplate = "Transform into a charming clay/claymation style. Soft rounded shapes, visible fingerprint textures. Warm handmade quality. Stop-motion aesthetic. Miniature diorama feeling.", Category = "Fun", IconEmoji = "\U0001F3FA", AccentColor = "#FF9800", IsActive = true, SortOrder = 13 },
            new StylePreset { Id = 14, Name = "Caricature", Description = "Exaggerated fun caricature", PromptTemplate = "Transform into a fun exaggerated caricature. Amplify distinctive facial features — larger eyes, exaggerated nose or chin, oversized head on smaller body. Bold expressive lines, vibrant colors. Humorous and flattering with professional caricature artist quality. Maintain recognizable likeness while exaggerating proportions.", Category = "Fun", IconEmoji = "\U0001F61C", AccentColor = "#E040FB", IsActive = true, SortOrder = 14 },
            new StylePreset { Id = 15, Name = "Neon Glow", Description = "Glowing neon light style", PromptTemplate = "Transform into a striking neon glow style. The subject outlined and filled with bright neon light tubes — electric blue, hot pink, purple, and cyan. Dark black background to maximize glow effect. Light bloom and lens flare around neon edges. Cyberpunk aesthetic with luminous glowing contours. Dramatic volumetric light rays.", Category = "Fun", IconEmoji = "\U0001F4A1", AccentColor = "#00E5FF", IsActive = true, SortOrder = 15 },
            new StylePreset { Id = 400, Name = "Photo Collage Mix", Description = "4-6 styled photo collage on 20x30 sheet", PromptTemplate = "Create a beautiful photo collage layout on a single 20×30 inch print-ready sheet. CRITICAL: Preserve EVERY person's exact facial features and identity across ALL panels. Take the uploaded source image and generate 4 to 6 distinct artistic variations of the SAME subject arranged in a visually striking collage grid layout. Each panel must show the same person(s) but in a DIFFERENT artistic style: Panel 1 — vivid oil painting with thick impasto brushstrokes and rich warm colors. Panel 2 — clean modern pop art with bold halftone dots, primary colors, and thick black outlines. Panel 3 — soft dreamy watercolor with translucent pastel washes and bleeding edges. Panel 4 — high-contrast dramatic black and white charcoal sketch with expressive strokes. Panel 5 (if space) — neon cyberpunk glow with electric pink and cyan light tubes on black. Panel 6 (if space) — elegant pencil line art with fine cross-hatching. Arrange panels in an asymmetric magazine-style grid with thin white borders (roughly 8-10px) between each panel. Vary panel sizes for visual interest — mix large feature panels with smaller accent panels. The overall composition should feel like a professional photo book spread or gallery wall arrangement. Clean white or soft grey background border around the entire collage. Print-quality high resolution with sharp details in every panel.", Category = "Fun", IconEmoji = "\U0001F5BC\uFE0F", AccentColor = "#7C4DFF", IsActive = true, SortOrder = 16 },
            new StylePreset { Id = 401, Name = "Emotions Collage", Description = "Same face with 6 dramatic emotions collage", PromptTemplate = "Create a stunning emotions portrait collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, skin tone, and identity across ALL panels — the same real person must be unmistakably recognizable in every frame. Generate 6 dramatic close-up face portraits of the SAME person, each showing a different powerful emotion: Panel 1 (large hero panel) — Pure Joy: an ecstatic beaming laugh with crinkled eyes, teeth showing, genuine radiant happiness, warm golden lighting. Panel 2 — Deep Thought: pensive contemplative expression, chin resting on hand, soft side-lighting with moody blue-grey tones. Panel 3 — Fierce Determination: intense focused gaze directly at camera, strong jaw set, dramatic chiaroscuro lighting with deep shadows. Panel 4 — Surprise & Wonder: wide eyes, raised eyebrows, slightly open mouth, bright ring-light catchlights, vivid colors. Panel 5 — Serene Peace: eyes gently closed, soft subtle smile, ethereal soft-focus backlighting with warm golden haze. Panel 6 — Bold Confidence: slight knowing smirk, one eyebrow raised, glamorous studio lighting with rim light highlighting the profile. Arrange in an asymmetric magazine editorial grid — one large hero panel occupying 40% of the sheet, remaining panels in varied smaller sizes. Thin white borders between panels. Each panel has cinematic movie-poster quality lighting and color grading. Professional portrait photography quality throughout.", Category = "Fun", IconEmoji = "\U0001F3AD", AccentColor = "#FF6F00", IsActive = true, SortOrder = 17 },
            new StylePreset { Id = 402, Name = "Decades Collage", Description = "Same face across 6 fashion eras collage", PromptTemplate = "Create a time-travel fashion decades collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, bone structure, and identity across ALL panels — the same real person must be unmistakably recognizable in every era. Generate 6 portraits of the SAME person styled in different iconic fashion decades: Panel 1 — 1950s Glamour: classic Hollywood golden age, victory rolls or slicked hair, red lipstick, pearl necklace, black and white with subtle warm sepia tones, soft-focus Hurrell glamour portrait lighting. Panel 2 — 1970s Disco: big voluminous hair, wide collar shirt or sequin top, gold hoop earrings, warm amber and orange color palette, groovy psychedelic background patterns. Panel 3 — 1980s Neon: bold geometric earrings, power shoulders, teased hair with hairspray, bright neon pink and electric blue color palette, MTV-era pop aesthetic. Panel 4 — 1990s Grunge: flannel shirt, choker necklace, natural messy hair, muted desaturated earth tones, moody alternative film-grain aesthetic. Panel 5 — 2000s Y2K: glossy lip gloss, butterfly clips or frosted tips, low-rise fashion, metallic silver and bubblegum pink, early digital camera flash aesthetic. Panel 6 — 2020s Modern: clean minimal Korean-inspired styling, glass-skin glow, subtle natural makeup, soft ring-light illumination, Instagram editorial quality. Arrange in a horizontal timeline-style grid flowing left to right with era labels subtly overlaid. Thin cream borders between panels. Each panel authentically captures its decade's photography style and color grading.", Category = "Fun", IconEmoji = "\u231B", AccentColor = "#FF8F00", IsActive = true, SortOrder = 18 },
            new StylePreset { Id = 403, Name = "World Cultures Collage", Description = "Same face in 6 cultural traditional attires", PromptTemplate = "Create a stunning world cultures portrait collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, skin tone, and identity across ALL panels — the same real person must be unmistakably recognizable in every cultural look. Generate 6 respectful, celebratory portraits of the SAME person wearing traditional attire from different world cultures: Panel 1 (large feature) — Indian Royal: ornate gold and ruby Rajasthani jewelry, embroidered silk fabric draped elegantly, maang tikka headpiece, warm saffron and gold palette, Diwali festive lighting. Panel 2 — Japanese Elegance: beautiful floral kimono with obi sash, delicate kanzashi hair ornament, cherry blossom backdrop, soft pink and white palette. Panel 3 — African Royalty: vibrant Ankara/Kente cloth wrap, bold beaded necklace and headwrap (gele), rich earthy reds, greens, and gold palette, warm sunset lighting. Panel 4 — Korean Hanbok: elegant silk jeogori and chima in cerise and jade, traditional binyeo hairpin, palace courtyard background, soft pastel tones. Panel 5 — Arabian Nights: luxurious embroidered kaftan with gold thread, ornate henna patterns on hands, jeweled headpiece, deep emerald and gold palette, lantern-lit ambiance. Panel 6 — European Renaissance: rich velvet and lace gown, pearl jewelry, elaborate updo hairstyle, Flemish oil painting quality with dramatic window light. Arrange in an elegant mosaic grid with thin gold foil borders between panels. Each panel is a respectful celebration of cultural beauty with authentic details and lighting.", Category = "Fun", IconEmoji = "\U0001F30D", AccentColor = "#00897B", IsActive = true, SortOrder = 19 },
            new StylePreset { Id = 404, Name = "Movie Poster Collage", Description = "Same face in 6 film genre poster styles", PromptTemplate = "Create a cinematic movie poster collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, and identity across ALL panels — the same real person must be the unmistakable star of every genre poster. Generate 6 dramatic portraits of the SAME person styled as the lead character in different movie genres: Panel 1 (large hero panel) — Action Blockbuster: intense determined expression, leather jacket, explosions and helicopters in background, dramatic orange and teal color grading, lens flare, bold action-movie typography space at top. Panel 2 — Romantic Drama: soft dreamy gaze, elegant outfit, golden hour sunset backdrop, warm rose-gold color palette, soft bokeh lights. Panel 3 — Horror/Thriller: half-face in shadow, wide terrified eyes, eerie green-blue desaturated tones, cracked mirror reflection, fog creeping in. Panel 4 — Sci-Fi Epic: futuristic armor or space suit, holographic HUD reflections on visor, distant planets and nebulae, electric blue and purple palette. Panel 5 — Film Noir Detective: fedora hat with shadow across eyes, trench coat, cigarette smoke wisps, dramatic black and white with high contrast, venetian blind shadow lines across face. Panel 6 — Comedy: big genuine laugh with bright cheerful expression, colorful casual outfit, bright saturated pop colors, confetti or paint splashes in background. Arrange in a dynamic asymmetric poster-wall grid with thin dark borders. Each panel includes subtle film-genre typography styling. Professional movie marketing art quality.", Category = "Fun", IconEmoji = "\U0001F3AC", AccentColor = "#D32F2F", IsActive = true, SortOrder = 20 },
            new StylePreset { Id = 405, Name = "Seasons Portrait Collage", Description = "Same face across 4 seasons with 2 bonus panels", PromptTemplate = "Create a breathtaking four-seasons portrait collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, skin tone, and identity across ALL panels — the same real person must be unmistakably recognizable in every season. Generate 6 portraits of the SAME person immersed in different seasonal atmospheres: Panel 1 (large feature) — Spring Bloom: subject surrounded by cherry blossom and magnolia petals gently falling, wearing a light floral outfit, soft pink and green pastel palette, fresh morning dew lighting, butterflies nearby, renewal and joy in expression. Panel 2 — Summer Golden: bright warm sunlight, wearing light breezy summer clothes, sunflower field or beach backdrop, rich golden-amber and turquoise palette, lens flare, confident happy expression. Panel 3 — Autumn Warmth: wrapped in a cozy scarf or sweater, surrounded by falling maple leaves in crimson, amber, and burnt orange, warm coffee-toned palette, soft diffused golden hour forest light. Panel 4 — Winter Magic: elegant winter attire, gentle snowflakes falling and resting on hair and shoulders, icy blue and silver palette with warm breath mist visible, twinkling fairy lights bokeh background, peaceful serene expression. Panel 5 — Monsoon Romance: rain droplets on face and hair, slightly wet clothes, dramatic grey sky with one shaft of golden light breaking through, reflective wet surfaces, cinematic rain-soaked beauty. Panel 6 — Twilight Dream: magical golden-hour-to-blue-hour transition, ethereal backlit silhouette with warm rim light on hair, fireflies and bokeh orbs floating, dreamy soft-focus romantic atmosphere. Arrange in an organic flowing grid — four main seasonal panels equally sized with two smaller accent panels. Thin white borders. Each panel captures the season's mood through lighting, color, and atmosphere.", Category = "Fun", IconEmoji = "\U0001F343", AccentColor = "#4CAF50", IsActive = true, SortOrder = 21 },
            new StylePreset { Id = 406, Name = "Fantasy Avatar Collage", Description = "Same face as 6 fantasy characters collage", PromptTemplate = "Create an epic fantasy character avatar collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, skin tone, and identity across ALL panels — the same real person must be unmistakably recognizable as every fantasy character. Generate 6 portraits of the SAME person transformed into different fantasy archetypes: Panel 1 (large hero panel) — Elven Royalty: elegant pointed ears, flowing silver-blonde hair with delicate leaf crown, ethereal luminous skin, wearing ornate elven armor with nature motifs, enchanted forest background with bioluminescent plants, soft green and gold palette. Panel 2 — Dark Warrior Knight: battle-scarred black plate armor with glowing red rune engravings, fierce war-paint on face, wielding a flaming sword, dark stormy castle background, dramatic crimson and steel palette. Panel 3 — Celestial Angel: magnificent white feathered wings spread wide, flowing white and gold robes, golden halo of light behind head, heavenly clouds and divine light rays, radiant white and gold palette. Panel 4 — Vampire Aristocrat: pale porcelain skin, sharp elegant features, blood-red eyes with vertical pupils, wearing Victorian gothic black velvet with high collar and ruby brooch, moonlit gothic castle, deep burgundy and midnight palette. Panel 5 — Ocean Siren/Mermaid: iridescent scales visible on shoulders and neck, flowing hair with seashell and pearl ornaments, underwater bioluminescent coral backdrop, aqua-teal and pearl palette. Panel 6 — Fire Mage Sorcerer: hands conjuring swirling flames and ember particles, glowing orange eyes, ornate mage robes with fire rune patterns, volcanic backdrop with lava rivers, intense orange and deep purple palette. Arrange in a dramatic asymmetric grid with thin dark obsidian borders. Each panel has cinematic fantasy game art quality with rich atmospheric lighting.", Category = "Fun", IconEmoji = "\U0001F9DD", AccentColor = "#6A1B9A", IsActive = true, SortOrder = 22 },
            new StylePreset { Id = 407, Name = "Career Day Collage", Description = "Same face in 6 iconic professional roles", PromptTemplate = "Create a fun career day portrait collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, skin tone, and identity across ALL panels — the same real person must be unmistakably recognizable in every professional role. Generate 6 portraits of the SAME person dressed and styled as different iconic professions: Panel 1 (large feature) — Astronaut: wearing a detailed NASA-style space suit with helmet visor open showing the face, Earth reflection visible in the visor glass, dramatic space station lighting with star field, deep blue and white palette. Panel 2 — Chef Master: crisp white double-breasted chef coat and tall toque hat, confidently holding a gleaming kitchen knife, warm kitchen with copper pots and flames in background, warm amber and white palette. Panel 3 — Fighter Pilot: aviator sunglasses pushed up on forehead, flight suit with patches and harness, confident smirk, fighter jet cockpit or runway with jets in background, cool steel-blue and orange palette. Panel 4 — Rock Star: leather jacket, electric guitar slung over shoulder, dramatic concert stage lighting with smoke machines and spotlights, audience silhouettes, electric purple and red palette. Panel 5 — Doctor/Surgeon: clean white coat with stethoscope, calm reassuring professional expression, modern hospital or operating room background with blue surgical lights, clinical blue-green and white palette. Panel 6 — Detective: classic trench coat and fedora, magnifying glass held near face with one eye enlarged through it, mysterious foggy street with vintage car and streetlamp, noir-style amber and shadow palette. Arrange in an engaging magazine-style grid with thin white borders. Each panel has professional-quality lighting and authentic costume details that sell the role convincingly.", Category = "Fun", IconEmoji = "\U0001F468\u200D\U0001F680", AccentColor = "#1565C0", IsActive = true, SortOrder = 23 },
            new StylePreset { Id = 408, Name = "Zodiac Signs Collage", Description = "Same face as 6 zodiac constellation portraits", PromptTemplate = "Create a mystical zodiac portrait collage on a single 20×30 inch print-ready sheet. CRITICAL: Preserve the subject's EXACT facial features, face shape, skin tone, and identity across ALL panels — the same real person must be unmistakably recognizable as every zodiac embodiment. Generate 6 portraits of the SAME person embodying different zodiac sign aesthetics: Panel 1 (large feature) — Leo: regal golden mane-like flowing hair with warm highlights, fierce confident expression, ornate gold crown and royal armor, lion silhouette in golden light behind, rich gold and amber palette with warm sun rays. Panel 2 — Scorpio: mysterious intense gaze, dark smoky eye makeup, black velvet draped outfit with scorpion brooch, dark water reflections and crimson roses, deep burgundy and black palette with subtle red glow. Panel 3 — Aquarius: futuristic iridescent outfit with water and air elements swirling around hands, electric blue streaks in hair, ethereal cosmic water-bearer pouring starlight, electric blue and silver palette. Panel 4 — Aries: bold warrior crown with ram horns, fierce determined expression, metallic red and gold armor, fire and sparks erupting in background, intense crimson and molten gold palette. Panel 5 — Pisces: dreamy ethereal expression, flowing hair intertwined with water streams and tiny fish, iridescent scales on shoulders, underwater ocean light, soft lavender and aqua-marine palette. Panel 6 — Sagittarius: adventurous smile, wielding a glowing bow and arrow aimed at the stars, centaur constellation shimmering behind, wearing explorer leather outfit, warm purple and starfield gold palette. Arrange in a celestial mosaic grid with thin midnight-blue borders and subtle star constellation lines connecting the panels. Each panel has a deep cosmic night-sky quality with constellation star patterns subtly overlaid.", Category = "Fun", IconEmoji = "\u2648", AccentColor = "#311B92", IsActive = true, SortOrder = 24 },

            // ── PhotoCollage ──
            new StylePreset { Id = 410, Name = "Torn Edge Story", Description = "3-panel torn-paper collage matching source mood", PromptTemplate = "DO NOT simply reproduce or lightly edit the source photo. You MUST generate a BRAND NEW composite image from scratch that is a COLLAGE of THREE SEPARATE PHOTOGRAPHS arranged vertically on a single canvas. Use the person's face and appearance from the source photo as reference ONLY for identity — every scene must be completely new and different. OUTPUT LAYOUT — vertical 2:3 portrait canvas divided into 3 stacked horizontal strips: TOP STRIP (35% of height): Generate a completely new wide-angle outdoor adventure scene — the same person standing next to a vintage vehicle on a scenic mountain road, or walking through a vibrant street market, or sitting on a dock at sunset. Full-body or three-quarter shot. Warm golden-hour lighting. MIDDLE STRIP (35% of height): Generate a completely new intimate close-up portrait — the same person in a cosy indoor setting like peeking out of a camping tent, leaning on a café window sill, or lying in a hammock. Contemplative or candid smiling expression. Soft diffused natural light. BOTTOM STRIP (30% of height): Generate a completely new rear-view or silhouette lifestyle shot — the same person from behind, arms raised or hands on head, gazing at a vast mountain valley, ocean horizon, or canyon overlook. Freedom and wanderlust mood. CRITICAL LAYOUT RULE: Between each strip, render a TORN PAPER EDGE — jagged irregular ripped-paper transition with visible white paper fibres and a faint drop shadow. The tear must look hand-ripped, NOT a straight line. Thin sliver of warm kraft/cream paper texture visible through each tear gap. COLOUR GRADING: All three panels must share a unified warm earthy colour palette — terracotta orange, olive green, dusty gold, muted teal, warm browns. Match the mood and dominant colours of the source image. Apply subtle film grain across the entire collage. The final output must clearly look like THREE DISTINCT PHOTOGRAPHS torn and stacked together, NOT one single photo.", Category = "PhotoCollage", IconEmoji = "\U0001F5BC\uFE0F", AccentColor = "#8D6E63", IsActive = true, SortOrder = 140 },
            new StylePreset { Id = 411, Name = "Greeting Card Collage", Description = "Personalised greeting card with photos and custom text", PromptTemplate = "DO NOT simply edit or reproduce the source photo. You MUST generate a BRAND NEW composite image that is a SCRAPBOOK-STYLE GREETING CARD COLLAGE on a single vertical 2:3 portrait canvas (like a 20\u00d730 inch print). Use the person in the source photo as the subject \u2014 preserve their EXACT face, hair, and appearance in every photo panel. LAYOUT \u2014 arrange 3 to 4 POLAROID-STYLE PHOTO PANELS scattered at slight random angles (tilted 2-8 degrees left or right) on the canvas. Each polaroid has a thick white border (especially wider at the bottom like a real instant photo). The photos should OVERLAP slightly in an organic scrapbook arrangement: Photo 1 (upper-left area, largest): a stylish three-quarter portrait of the subject, natural warm lighting. Photo 2 (upper-right, medium): a candid lifestyle shot \u2014 the subject laughing, walking, or in an everyday moment. Photo 3 (lower-right, medium): a close-up portrait with a warm genuine smile. Photo 4 (lower-left, optional smaller): a full-body or creative angle shot. DECORATIVE ELEMENTS scattered around the photos: realistic pink peonies and roses (soft pink, blush, and cream tones), green botanical leaves and fern fronds, small strips of washi tape (red gingham check pattern) holding photos in place, and tiny floral sprigs tucked behind the polaroids. LARGE CALLIGRAPHY TEXT: In the open space (centre-left area between the photos), render the text '{{OCCASION}}' in elegant flowing hand-lettered brush script font \u2014 dark charcoal/black ink colour, large and prominent, with natural brush stroke thickness variations. This must be clearly readable. HANDWRITTEN NOTE: In the lower portion of the canvas, render a small kraft-brown paper card/note (slightly tilted) with handwritten cursive text reading: '{{MESSAGE}}' \u2014 in a warm dark brown ink, casual handwriting style. BACKGROUND: warm cream/off-white textured paper with very faint vintage script writing watermark pattern. Overall colour palette: warm cream, soft blush pink, sage green, kraft brown \u2014 matching the mood and tones of the source photo. The final image must look like a beautifully styled flat-lay scrapbook greeting card photograph.", Category = "PhotoCollage", IconEmoji = "\U0001F48C", AccentColor = "#E91E63", IsActive = true, SortOrder = 141 },
            new StylePreset { Id = 420, Name = "Birthday Bash Burst", Description = "Festive birthday collage with confetti, balloons, and fun panels", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW BIRTHDAY PARTY COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 5 panels arranged in a dynamic burst pattern. Panel 1 (centre, largest, circular frame): a glamorous portrait of the subject wearing a party hat or tiara, big smile, confetti falling around them. Panel 2 (upper-left, tilted 5\u00b0): the subject blowing out candles on a birthday cake, warm candlelight glow. Panel 3 (upper-right, tilted -5\u00b0): the subject laughing with arms raised in celebration. Panel 4 (lower-left, small square): a close-up of the subject with a surprised joyful expression, opening a gift. Panel 5 (lower-right, small square): full-body shot of the subject dancing or jumping with balloons. DECORATIONS: colourful helium balloons (gold, pink, blue) floating around panels, scattered confetti and streamers, illustrated star bursts, glitter particle overlay. TEXT: Render '{{OCCASION}}' in large bold fun bubble-letter font across the top \u2014 bright pink or gold with a slight 3D shadow effect. Render '{{MESSAGE}}' in a playful handwritten font on a small banner ribbon at the bottom. BACKGROUND: warm gradient from soft pink to lavender with bokeh light circles. Overall mood: joyful, celebratory, vibrant.", Category = "PhotoCollage", IconEmoji = "\U0001F382", AccentColor = "#FF6B6B", IsActive = true, SortOrder = 142 },
            new StylePreset { Id = 421, Name = "Golden Anniversary", Description = "Elegant romantic collage with gold foil accents and roses", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW ELEGANT ANNIVERSARY COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 4 panels in a symmetric arrangement. Panel 1 (left, tall portrait): the subject in elegant formal attire, standing in a garden with soft golden-hour backlighting, romantic three-quarter pose. Panel 2 (upper-right, square): a close-up portrait with a warm loving smile, soft-focus floral background. Panel 3 (lower-right, square): the subject sitting on an ornate bench or by a fountain, contemplative elegant pose. Panel 4 (centre overlay, small oval with gold ornate frame): an intimate close-up, eyes sparkling. DECORATIONS: gold foil filigree borders and corner ornaments, scattered red and blush rose petals, thin gold line separators between panels, small illustrated hearts. TEXT: Render '{{OCCASION}}' in elegant serif font with gold metallic effect \u2014 centred between the panels. Render '{{MESSAGE}}' in flowing italic calligraphy on a cream banner with gold edges at the bottom. BACKGROUND: deep burgundy to cream gradient with a subtle damask pattern watermark. Colour palette: gold, burgundy, cream, blush pink. Overall mood: romantic, timeless, luxurious.", Category = "PhotoCollage", IconEmoji = "\U0001F48D", AccentColor = "#C9A84C", IsActive = true, SortOrder = 143 },
            new StylePreset { Id = 422, Name = "Cap & Tassel Graduation", Description = "Academic graduation collage with formal grid and achievement banners", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW GRADUATION COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 6 panels in a structured academic grid. Panel 1 (top, wide panoramic): the subject in graduation cap and gown, tossing the cap in the air on a grand university campus with classical architecture. Panel 2 (middle-left, square): a formal portrait \u2014 the subject holding a diploma scroll, proud expression, studio-quality lighting. Panel 3 (middle-right, square): the subject in cap and gown walking through a tree-lined campus path, golden autumn light. Panel 4 (bottom-left, small portrait): the subject studying at a desk with books, determined expression \u2014 the journey. Panel 5 (bottom-centre, small portrait): the subject in professional attire, confident power pose \u2014 the future. Panel 6 (bottom-right, small portrait): candid shot of the subject celebrating with confetti, pure joy. DECORATIONS: navy and gold colour blocking borders, illustrated diploma scrolls and laurel wreaths, small star scatter accents, thin gold rule lines between panels. TEXT: Render '{{OCCASION}}' in bold uppercase serif font \u2014 navy blue with gold outline \u2014 as a banner across the top. Render '{{MESSAGE}}' in elegant script below the panels on a cream ribbon. BACKGROUND: navy blue with subtle geometric pattern. Colour palette: navy, gold, white, cream.", Category = "PhotoCollage", IconEmoji = "\U0001F393", AccentColor = "#1B3A6B", IsActive = true, SortOrder = 144 },
            new StylePreset { Id = 423, Name = "Passport Stamps Adventure", Description = "Travel wanderlust collage with map background and vintage stamps", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW TRAVEL ADVENTURE COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 5 panels scattered organically as if travel snapshots tossed on a map. Panel 1 (centre-left, largest, slightly tilted): the subject with a backpack, standing before an iconic landmark (Eiffel Tower, Colosseum, or similar), golden-hour lighting. Panel 2 (upper-right, polaroid-style with white border): the subject sitting at a quaint European caf\u00e9, enjoying coffee. Panel 3 (lower-left, rounded corners): the subject hiking on a mountain trail, vast landscape behind them. Panel 4 (lower-right, tilted -8\u00b0): the subject at a tropical beach, relaxed and happy, turquoise water. Panel 5 (upper-left, small square): the subject in a busy Asian street market, vibrant colours and lanterns. DECORATIONS: vintage world map as background (muted sepia tones), circular passport stamp overlays on corners of each panel (with dates and city names), decorative compass rose, illustrated airplane trail dotted line connecting the panels, airmail stripe border on some panels. No text placeholders. BACKGROUND: aged parchment world map texture with coffee-stain effects. Colour palette: warm sepia, teal, terracotta, muted greens. Overall mood: adventurous, nostalgic, wanderlust.", Category = "PhotoCollage", IconEmoji = "\u2708\uFE0F", AccentColor = "#2E8B57", IsActive = true, SortOrder = 145 },
            new StylePreset { Id = 424, Name = "Family Gallery Wall", Description = "Cosy gallery wall collage with mismatched frames on a warm background", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FAMILY GALLERY WALL COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 7 panels arranged as mismatched picture frames on a warm-toned wall. Frame 1 (centre, largest, ornate gold frame): a warm family-style portrait of the subject, smiling naturally in a cosy living room setting. Frame 2 (upper-left, simple white frame, portrait): the subject cooking in a kitchen, candid and happy. Frame 3 (upper-right, rustic wood frame, square): the subject reading a book on a window seat, soft natural light. Frame 4 (left, thin black frame, landscape): the subject walking in a park during autumn, golden leaves. Frame 5 (right, vintage oval frame): close-up portrait with a gentle smile, warm soft focus. Frame 6 (lower-left, distressed wood frame, small): the subject gardening or doing a hobby, hands busy. Frame 7 (lower-right, modern thin frame, small): the subject laughing, candid moment of pure joy. DECORATIONS: string lights draped across the top of the wall, small potted plant on a floating shelf between frames, the wall itself has a warm honey-beige paint texture with subtle imperfections. Each frame style is DIFFERENT (ornate, simple, rustic, vintage). No text placeholders. BACKGROUND: warm honey-beige painted wall texture. Colour palette: warm browns, honey, cream, forest green, burnt orange.", Category = "PhotoCollage", IconEmoji = "\U0001F3E1", AccentColor = "#D4845A", IsActive = true, SortOrder = 146 },
            new StylePreset { Id = 425, Name = "Vision Board Manifest", Description = "Motivational vision board with magazine cutouts and inspiring words", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW VISION BOARD COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 8 panels arranged in an irregular magazine-cutout style on a cork board background. Panel 1 (centre-top, largest): the subject in powerful confident pose, wearing stylish professional attire, city skyline behind them. Panel 2 (upper-left, tilted 5\u00b0): the subject working out or doing yoga, healthy and strong. Panel 3 (upper-right, small): the subject at a desk with a laptop, productive and focused. Panel 4 (middle-left, rectangular): the subject travelling \u2014 standing at an airport or with luggage, excited. Panel 5 (middle-right, circular): close-up of the subject with a radiant smile, glowing skin. Panel 6 (lower-left, square): the subject in a luxury car or beautiful home, aspirational lifestyle. Panel 7 (lower-centre, tilted): the subject celebrating an achievement, arms raised. Panel 8 (lower-right, small): the subject with friends, laughing together. DECORATIONS: colourful washi tape strips holding panels, magazine-style word cutouts scattered between panels (DREAM, CREATE, BELIEVE, THRIVE, MANIFEST) in bold mixed fonts, star and checkmark stickers, small illustrated icons (rocket, diamond, crown). TEXT: Render '{{MESSAGE}}' in large bold motivational poster font across an open area. BACKGROUND: light cork board texture with pin holes. Colour palette: bright pink, gold, teal, white, black typography. Overall mood: empowering, aspirational, energetic.", Category = "PhotoCollage", IconEmoji = "\u2728", AccentColor = "#E91E8C", IsActive = true, SortOrder = 147 },
            new StylePreset { Id = 426, Name = "Vogue Editorial Spread", Description = "High-fashion magazine editorial layout with bold typography", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FASHION EDITORIAL COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 4 panels in an asymmetric magazine spread. Panel 1 (left side, full height, 60% width): a dramatic full-body high-fashion editorial shot of the subject in a couture outfit, striking model pose, dramatic studio lighting with strong shadows. Panel 2 (upper-right, square): an intense close-up beauty shot, flawless skin, bold makeup, piercing gaze. Panel 3 (middle-right, wide landscape): the subject walking on a runway or in an architectural space, dynamic movement, editorial energy. Panel 4 (lower-right, square): an artistic profile silhouette shot, dramatic backlighting creating a rim-light effect. DECORATIONS: thin elegant black rule lines separating right panels, mock magazine masthead at very top in ultra-thin uppercase tracking (VOGUE ARTFORGE), small page number and section label. TEXT: Render '{{OCCASION}}' in massive ultra-bold condensed sans-serif font overlaid semi-transparently on the hero panel \u2014 black or white depending on contrast. BACKGROUND: pure white with clean negative space. Colour palette: black, white, one single accent colour pulled from the source photo. Overall mood: high fashion, editorial, powerful, minimalist.", Category = "PhotoCollage", IconEmoji = "\U0001F457", AccentColor = "#1A1A1A", IsActive = true, SortOrder = 148 },
            new StylePreset { Id = 427, Name = "Minimal Nordic Grid", Description = "Clean 9-panel grid with generous white space and muted tones", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW MINIMALIST GRID COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 9 panels in a perfect 3\u00d73 symmetric grid with equal white gutters (approximately 3% canvas width between each panel). All panels are identical square size. Panel 1 (top-left): soft portrait of the subject in neutral tones, looking away, natural window light. Panel 2 (top-centre): close-up of the subject's hands holding a coffee cup or book, warm minimal setting. Panel 3 (top-right): the subject from behind, walking on a quiet minimalist street or hallway. Panel 4 (middle-left): the subject sitting in a clean Scandinavian-style interior, reading or resting. Panel 5 (middle-centre): a direct-gaze close-up portrait, soft natural light, gentle expression. Panel 6 (middle-right): the subject near a window, silhouette partially lit, contemplative. Panel 7 (bottom-left): the subject in a nature setting \u2014 misty forest or lake shore, solitude. Panel 8 (bottom-centre): an architectural detail shot with the subject small in frame, negative space. Panel 9 (bottom-right): the subject smiling softly, warm candid moment, slightly overexposed. DECORATIONS: NONE \u2014 absolutely clean, no borders beyond the white gutters, no text, no stickers. Only a thin hairline border around the entire grid. BACKGROUND: pure white. Colour palette: muted sage, warm grey, cream, soft blush \u2014 desaturated and cohesive across all 9 panels. Overall mood: calm, serene, Scandinavian minimalism.", Category = "PhotoCollage", IconEmoji = "\u25AA\uFE0F", AccentColor = "#B8C4BB", IsActive = true, SortOrder = 149 },
            new StylePreset { Id = 428, Name = "Baby Milestone Journey", Description = "Soft whimsical baby milestone collage with pastel decorations", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW BABY MILESTONE COLLAGE on a vertical 2:3 portrait canvas. Use the person (baby or child) from the source photo \u2014 preserve their EXACT face and appearance. LAYOUT: 6 panels in a 2-column staggered scrapbook layout. Panel 1 (top-left, large): the baby/child in a white onesie or cute outfit, sitting on a fluffy blanket, big curious eyes, soft studio lighting. Panel 2 (top-right, medium, slightly lower): the baby/child reaching for a toy or playing with blocks, candid joyful moment. Panel 3 (middle-left, medium): the baby/child crawling or taking first steps, milestone moment, proud expression. Panel 4 (middle-right, large): a close-up of the baby/child's face with a big gummy smile, sparkling eyes. Panel 5 (bottom-left, medium): the baby/child being held up, arms spread like flying, pure delight. Panel 6 (bottom-right, medium): the baby/child sleeping peacefully, angelic, soft warm glow. DECORATIONS: soft watercolour pastel washes between panels (pink, mint, lavender), illustrated clouds and tiny stars as spacers, small crescent moon, cute illustrated animals (bunny, teddy bear, duckling) peeking around panel edges, milestone number badges (1, 2, 3...) as small circles on each panel. TEXT: Render '{{OCCASION}}' in soft rounded playful font \u2014 pastel pink or blue \u2014 at the top. Render '{{MESSAGE}}' in gentle handwritten cursive on a small cloud shape at the bottom. BACKGROUND: soft cream with very faint polka dot pattern. Colour palette: pastel pink, mint green, lavender, cream, baby blue.", Category = "PhotoCollage", IconEmoji = "\U0001F37C", AccentColor = "#F9C6D0", IsActive = true, SortOrder = 150 },
            new StylePreset { Id = 429, Name = "A Day in My Life", Description = "Cinematic film-strip collage capturing morning-to-night moments", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FILM-STRIP DAY-IN-THE-LIFE COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 6 panels arranged as a vertical film strip running down the canvas. Each panel is a wide cinematic landscape-ratio frame. Panel 1 (top, labelled 7:00 AM): the subject waking up, stretching in bed, soft golden morning light streaming through curtains. Panel 2 (labelled 9:00 AM): the subject having breakfast at a sunny kitchen table or caf\u00e9, coffee in hand. Panel 3 (labelled 12:00 PM): the subject at work or creative activity \u2014 at a desk, painting, or in a meeting, focused and productive. Panel 4 (labelled 3:00 PM): the subject outdoors during a break \u2014 walking in a park, at a caf\u00e9 terrace, or exercising, relaxed energy. Panel 5 (labelled 7:00 PM): the subject at dinner \u2014 cooking at home or at a restaurant, warm ambient lighting. Panel 6 (labelled 10:00 PM): the subject relaxing at night \u2014 reading on a couch, watching stars from a balcony, or winding down, cosy and peaceful. DECORATIONS: authentic 35mm film perforation holes running along both sides of the strip, dark brown film border, each panel has a small timestamp label in monospace font (Courier style) below it. Thin frame lines between each panel. BACKGROUND: dark espresso brown filmstrip border with the canvas showing between the perforations. Colour palette: warm cinematic tones \u2014 golden morning, bright midday, amber evening, cool blue night, progressing naturally. Overall mood: cinematic, storytelling, warm nostalgia.", Category = "PhotoCollage", IconEmoji = "\U0001F39E\uFE0F", AccentColor = "#3D2B1F", IsActive = true, SortOrder = 151 },
            new StylePreset { Id = 430, Name = "Retro Polaroid Party", Description = "Playful scattered Polaroids on a colourful background with stickers", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW RETRO POLAROID PARTY COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 6 Polaroid-frame panels scattered at random rotations (-15\u00b0 to +15\u00b0) across the canvas, overlapping slightly. Each polaroid has a thick white border (extra wide at the bottom for captions). Polaroid 1 (centre, largest, tilted 3\u00b0): the subject making a fun silly face, peace sign, bright colourful background. Polaroid 2 (upper-left, tilted -10\u00b0): the subject laughing with head thrown back, pure joy. Polaroid 3 (upper-right, tilted 8\u00b0): a group-style shot of the subject with arms around friends (generate generic friends), party setting. Polaroid 4 (lower-left, tilted -5\u00b0): the subject dancing or jumping, dynamic action shot, motion energy. Polaroid 5 (lower-right, tilted 12\u00b0): close-up of the subject blowing a kiss or winking, playful. Polaroid 6 (bottom-centre, tilted -3\u00b0): the subject posing with sunglasses or a fun prop, cool and confident. DECORATIONS: colourful illustrated stickers scattered around (hearts, stars, smiley faces, rainbows, lips), small doodle drawings, glitter scatter effect, each Polaroid has a handwritten-style date or fun caption on the white bottom border. TEXT: Render '{{MESSAGE}}' as a large playful hand-drawn text across an open area, in bright colours with a slight wobble effect. BACKGROUND: bright retro pattern \u2014 colourful chevron, confetti, or geometric shapes. Colour palette: bright yellow, hot pink, electric blue, orange, white. Overall mood: fun, nostalgic, playful party.", Category = "PhotoCollage", IconEmoji = "\U0001F4F8", AccentColor = "#FFD700", IsActive = true, SortOrder = 152 },
            new StylePreset { Id = 431, Name = "Luxury Portfolio", Description = "High-end portfolio layout with hero panel and editorial grid", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW LUXURY PORTFOLIO COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 5 panels in an asymmetric editorial arrangement. Panel 1 (left side, full height, 55% width): a stunning full-body hero shot of the subject in elegant professional attire, confident powerful pose, clean studio backdrop with soft gradient lighting. Panel 2 (upper-right, square): a beauty close-up \u2014 perfect lighting, sharp focus on face, professional headshot quality. Panel 3 (middle-right, square): the subject in a different outfit, three-quarter pose, architectural or luxury interior background. Panel 4 (lower-right, landscape): the subject in motion \u2014 walking confidently through a modern space, editorial energy. Panel 5 (bottom, thin strip spanning right column): an artistic detail shot \u2014 the subject's silhouette or a creative angle with dramatic light. DECORATIONS: thin gold rule lines separating the right-side panels, small monogram or logo placeholder in upper-right corner, clean negative space. TEXT: Render '{{OCCASION}}' in ultra-thin uppercase widely-spaced sans-serif font as a small header label. BACKGROUND: warm cream or light grey. Colour palette: cream, gold, charcoal, one accent colour from the source photo. Overall mood: luxurious, professional, editorial, aspirational.", Category = "PhotoCollage", IconEmoji = "\U0001F4BC", AccentColor = "#8B7355", IsActive = true, SortOrder = 153 },
            new StylePreset { Id = 432, Name = "BFFs Friendship Collage", Description = "Warm energetic collage for friends with colour-block backgrounds", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FRIENDSHIP COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 5 panels arranged in a diagonal zigzag from top-left to bottom-right, each slightly overlapping the next. Panel 1 (upper-left, large, tilted 3\u00b0): the subject and a friend (generate a friendly-looking companion) taking a selfie together, big smiles, fun background. Panel 2 (upper-right, medium, tilted -4\u00b0): the subject and friends at a caf\u00e9 or restaurant, laughing over food and drinks. Panel 3 (centre, largest, straight): the subject in the middle of a friend group, arms linked, walking down a sunny street, candid joyful energy. Panel 4 (lower-left, medium, tilted 5\u00b0): the subject and a friend doing a fun activity \u2014 shopping, dancing, or at a concert, dynamic and energetic. Panel 5 (lower-right, medium, tilted -3\u00b0): a heartfelt moment \u2014 the subject and friends in a group hug or sitting together watching a sunset, warm and emotional. DECORATIONS: bold colour-blocked background sections in complementary hues (purple, teal, coral, yellow) behind each panel, illustrated heart bursts and star doodles in the gaps, small friendship-themed stickers (BFF, heart hands), confetti scatter. TEXT: Render '{{MESSAGE}}' in large outlined bubble-letter word art across an open space \u2014 vibrant purple or teal. BACKGROUND: multicolour geometric colour blocks. Colour palette: purple, teal, coral, sunshine yellow, white. Overall mood: warm, energetic, celebratory, friendship.", Category = "PhotoCollage", IconEmoji = "\U0001F46F", AccentColor = "#7B2D8B", IsActive = true, SortOrder = 154 },
            new StylePreset { Id = 433, Name = "Season's Greetings Card", Description = "Festive holiday greeting card with seasonal borders and elegant text", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW HOLIDAY GREETING CARD COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo \u2014 preserve their EXACT face, hair, and appearance. LAYOUT: 4 photo panels arranged in an L-shape flanking a central text area. Panel 1 (upper-left, portrait): the subject in a cosy winter sweater, standing by a decorated Christmas tree or fireplace, warm candlelight and fairy lights. Panel 2 (lower-left, square): the subject in winter outdoor setting \u2014 snow falling, wearing a scarf and beanie, rosy cheeks, happy smile. Panel 3 (upper-right, square): a close-up portrait of the subject holding a wrapped gift or a mug of hot cocoa, warm intimate lighting. Panel 4 (lower-right, portrait): the subject in elegant holiday party attire, festive background with bokeh lights and ornaments. CENTRAL TEXT AREA: a tall centre panel reserved for text, framed by the 4 photo panels. TEXT: Render '{{OCCASION}}' in large elegant serif font with gold metallic effect \u2014 centred and prominent. Render '{{MESSAGE}}' below in flowing italic calligraphy, dark green or gold. DECORATIONS: illustrated pine branches and holly berries bordering the entire canvas edge, gold foil snowflake scatter, small red berries and pinecone accents, thin gold ornamental border around each photo panel. BACKGROUND: deep forest green with subtle snowflake pattern. Colour palette: forest green, gold, red, cream, warm white fairy-light glow. Overall mood: festive, elegant, warm, celebratory.", Category = "PhotoCollage", IconEmoji = "\U0001F384", AccentColor = "#165B33", IsActive = true, SortOrder = 155 },

            // Professional (6)
            new StylePreset { Id = 16, Name = "Sketch", Description = "Detailed pencil sketch", PromptTemplate = "Transform into a detailed pencil sketch. Fine graphite linework on white paper. Cross-hatching for shadows. Detailed texture work. Professional illustration quality. Clean precise lines with artistic shading.", Category = "Professional", IconEmoji = "\u270F\uFE0F", AccentColor = "#78909C", IsActive = true, SortOrder = 16 },
            new StylePreset { Id = 17, Name = "3D Render", Description = "Hyper-detailed 3D render", PromptTemplate = "Transform into a hyper-detailed 3D render. Smooth subsurface scattering on skin. Ray-traced reflections and global illumination. Octane/Blender quality. Sharp geometric detail. Photorealistic material textures.", Category = "Professional", IconEmoji = "\U0001F3B2", AccentColor = "#5C6BC0", IsActive = true, SortOrder = 17 },
            new StylePreset { Id = 18, Name = "Vector Art", Description = "Clean geometric vector style", PromptTemplate = "Transform into clean vector illustration. Flat colors, smooth curves, geometric precision. Bold simplified shapes. Modern graphic design aesthetic. Print-ready quality.", Category = "Professional", IconEmoji = "\U0001F4D0", AccentColor = "#26A69A", IsActive = true, SortOrder = 18 },
            new StylePreset { Id = 19, Name = "Line Art", Description = "Elegant ink line illustration", PromptTemplate = "Transform into elegant line art illustration. Single weight or varying line thickness. No fill colors, just expressive linework. Clean, minimal, sophisticated. Professional ink illustration.", Category = "Professional", IconEmoji = "\U0001F4DD", AccentColor = "#546E7A", IsActive = true, SortOrder = 19 },
            new StylePreset { Id = 20, Name = "Gold/Metallic", Description = "Golden statue effect", PromptTemplate = "Transform into a stunning golden metallic statue. The subject rendered as a polished gold sculpture with realistic metallic reflections and specular highlights. Rich 24-karat gold surface with subtle variations in tone. Dramatic studio lighting emphasizing the metallic sheen. Museum pedestal display quality. Luxurious and prestigious.", Category = "Professional", IconEmoji = "\U0001F451", AccentColor = "#FFD600", IsActive = true, SortOrder = 20 },
            new StylePreset { Id = 21, Name = "Paparazzi", Description = "Celebrity red carpet shot", PromptTemplate = "Transform into a glamorous celebrity paparazzi photograph. Dramatic camera flash lighting with slight overexposure. Red carpet or premiere event backdrop with bokeh lights. The subject looking camera-ready with star quality presence. High-fashion editorial quality. Slight motion blur suggesting a candid caught moment. Magazine cover worthy.", Category = "Professional", IconEmoji = "\U0001F4F8", AccentColor = "#D32F2F", IsActive = true, SortOrder = 21 },
            new StylePreset { Id = 26, Name = "Cinematic B&W Profile", Description = "Dramatic B&W layered side-profile portrait", PromptTemplate = "Identify every person in the source photo. The output MUST contain the EXACT same number of people — do NOT skip or merge anyone. CRITICAL: Each person has a UNIQUE face — different age, gender, face shape, nose, jawline, forehead, hair. You MUST preserve each person's individual facial identity exactly. Do NOT make them look alike. Render each person as a dramatic side profile facing left. Stack all profiles vertically against a pure black background, largest at top to smallest at bottom, slightly overlapping. Each face must look exactly like that specific person from the source — a viewer should be able to identify who is who. Black and white high-contrast monochrome. Dramatic rim lighting from one side. Deep blacks, bright highlights. Cinematic editorial portrait.", Category = "Professional", IconEmoji = "\U0001F39E\uFE0F", AccentColor = "#212121", IsActive = true, SortOrder = 22 },

            // Abstract (4)
            new StylePreset { Id = 22, Name = "Stained Glass", Description = "Cathedral stained glass design", PromptTemplate = "Transform into a stained glass window design. Bold black lead lines, jewel-toned translucent colors. Geometric segmentation. Cathedral-quality craftsmanship. Light shining through colored glass.", Category = "Abstract", IconEmoji = "\U0001FA9F", AccentColor = "#AB47BC", IsActive = true, SortOrder = 22 },
            new StylePreset { Id = 23, Name = "Low Poly", Description = "Geometric faceted art", PromptTemplate = "Transform into low-poly 3D art style. Geometric faceted surfaces, minimal polygon count. Clean flat-shaded triangles. Modern minimalist aesthetic. Vibrant gradient colors across faces.", Category = "Abstract", IconEmoji = "\U0001F537", AccentColor = "#1E88E5", IsActive = true, SortOrder = 23 },
            new StylePreset { Id = 24, Name = "Clouds/Dreamy", Description = "Ethereal cloud portrait", PromptTemplate = "Transform into an ethereal dreamy cloud artwork. The subject's form composed of soft billowing clouds and mist against a pastel sky. Wispy cirrus clouds trace the features and contours. Golden hour sunlight illuminating the cloud formations. Heavenly, serene, and otherworldly atmosphere. Soft focus with luminous edges.", Category = "Abstract", IconEmoji = "\u2601\uFE0F", AccentColor = "#90CAF9", IsActive = true, SortOrder = 24 },
            new StylePreset { Id = 25, Name = "Surreal", Description = "Dali-inspired surrealism", PromptTemplate = "Transform into a surrealist artwork inspired by Salvador Dali. Dreamlike impossible geometry and melting forms. The subject existing in a bizarre landscape with floating objects, distorted perspectives, and impossible architecture. Rich detailed oil painting technique with hyperreal textures in an unreal context. Mysterious, thought-provoking, visually stunning.", Category = "Abstract", IconEmoji = "\U0001F300", AccentColor = "#FF6F00", IsActive = true, SortOrder = 25 },

            // Oil Painting Niche Styles (3)
            new StylePreset { Id = 100, Name = "Palette Knife Impasto", Description = "Thick textured palette knife oil painting", PromptTemplate = "Transform into a vibrant palette knife impasto oil painting. CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. Thick, heavily textured paint applied with a palette knife creating bold three-dimensional ridges and peaks on the canvas. Rich saturated colors \u2014 deep cobalt blues, cadmium reds, golden yellows blended directly on the surface. Visible thick paint strokes catching light from different angles. Inspired by Leonid Afremov's luminous rainy-city style. Modern impressionistic oil painting with dramatic color contrasts and tactile texture. Gallery-quality contemporary oil art.", Category = "Artistic", IconEmoji = "\U0001F52A", AccentColor = "#E65100", IsActive = true, SortOrder = 9 },
            new StylePreset { Id = 101, Name = "Flemish Oil Masters", Description = "Jan van Eyck ultra-detailed luminous oil painting", PromptTemplate = "Transform into an exquisite Flemish Old Masters oil painting in the style of Jan van Eyck and Rogier van der Weyden. CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. Microscopic hyper-detailed rendering \u2014 every strand of hair, fabric thread, and skin pore meticulously painted. Luminous jewel-like colors achieved through dozens of transparent oil glazing layers on white gesso ground. Rich saturated hues of lapis lazuli blue, vermillion red, and emerald green. Atmospheric perspective with crystalline clarity. Soft diffused northern light from a window. Elaborate textures \u2014 velvet, fur, polished metal, translucent gems rendered with photographic precision. 15th century Netherlandish masterpiece quality.", Category = "Artistic", IconEmoji = "\U0001F48E", AccentColor = "#1B5E20", IsActive = true, SortOrder = 10 },
            new StylePreset { Id = 102, Name = "Expressionist Oil", Description = "Van Gogh & Munch bold emotional oil painting", PromptTemplate = "Transform into a bold Expressionist oil painting in the style of Van Gogh and Edvard Munch. CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. Thick swirling brushstrokes radiating with emotional energy. Vivid distorted colors \u2014 electric blues, burning oranges, deep purples that convey raw psychological intensity. Bold visible directional brushwork creating rhythmic movement across the canvas. Starry Night-inspired turbulent skies and pulsating backgrounds. Forms slightly abstracted and elongated with emotional distortion. Dramatic complementary color contrasts heightening the mood. Post-Impressionist modern art masterpiece quality.", Category = "Artistic", IconEmoji = "\U0001F30A", AccentColor = "#FF6D00", IsActive = true, SortOrder = 11 },

            // Indianised Oil Painting Styles (3)
            new StylePreset { Id = 103, Name = "Ravi Varma Oil", Description = "Raja Ravi Varma classical Indian oil portraiture", PromptTemplate = "Transform into a classical Indian oil painting in the style of Raja Ravi Varma. CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. European academic realism blended with Indian aesthetic sensibility. Rich saturated oil colors with luminous skin tones and smooth blending. Subjects dressed in traditional Indian attire \u2014 silk sarees with gold borders, ornate jewelry, and classical drapery. Warm golden lighting with soft shadows. Lush Indian botanical background \u2014 tropical flowers, temple architecture, or palatial interiors. Museum-quality Indian fine art masterpiece in the tradition of the father of modern Indian art.", Category = "Artistic", IconEmoji = "\U0001FAB7", AccentColor = "#B71C1C", IsActive = true, SortOrder = 12 },
            new StylePreset { Id = 104, Name = "Tanjore Gold Oil", Description = "South Indian Thanjavur gold-leaf oil painting", PromptTemplate = "Transform into a magnificent Tanjore oil painting style from South India. CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. Rich embossed gold leaf highlights on jewelry, crowns, and ornamental borders. Vibrant jewel-tone colors \u2014 deep red, royal blue, emerald green, and brilliant gold. Semi-precious stone-like gem embellishments on the surface. Ornate decorative arch framing with intricate floral and geometric patterns. Round gentle facial features with large expressive eyes. Traditional South Indian temple art aesthetic with divine golden radiance. Thanjavur painting masterpiece quality.", Category = "Artistic", IconEmoji = "\U0001F6D5", AccentColor = "#FF8F00", IsActive = true, SortOrder = 13 },
            new StylePreset { Id = 105, Name = "Bengal School Oil", Description = "Abanindranath Tagore dreamlike Indian oil art", PromptTemplate = "Transform into a dreamlike Bengal School oil painting in the style of Abanindranath Tagore and Nandalal Bose. CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. Soft ethereal wash-like quality with muted pastel and earth tones \u2014 dusty rose, sage green, warm ochre, and misty blue. Gentle flowing brushstrokes with dreamy atmospheric haze. Indian nationalist art aesthetic celebrating indigenous beauty and mythology. Delicate elongated figures with graceful poses reminiscent of Ajanta cave murals. Subtle gold accents and soft diffused lighting. Romantic, nostalgic, spiritually evocative. Early 20th century Indian art renaissance masterpiece quality.", Category = "Artistic", IconEmoji = "\U0001F3A8", AccentColor = "#5D4037", IsActive = true, SortOrder = 14 },

            // Bapu Bomma — Telugu iconic art
            new StylePreset { Id = 106, Name = "Bapu Bomma", Description = "Legendary Telugu artist Bapu's iconic illustration style", PromptTemplate = "Transform into the iconic Bapu Bomma illustration style of legendary Telugu artist Bapu (Sattiraju Lakshmi Narayana). CRITICAL: Preserve EVERY person in the image \u2014 do NOT remove, merge, or skip anyone. Keep all people at their correct relative sizes and positions. Distinctive clean precise ink linework with elegant flowing contours. Beautiful rounded faces with large expressive almond-shaped eyes, delicate pointed chins, and gentle smiles. Slender graceful figures with classical Indian poses and expressive hand gestures. Traditional South Indian attire \u2014 flowing silk sarees with intricate border patterns, jasmine flowers in hair, temple jewelry. Soft pastel coloring with warm skin tones \u2014 peach, cream, and golden hues. Minimal uncluttered backgrounds with subtle floral or nature motifs. The unmistakable Bapu aesthetic \u2014 grace, beauty, and cultural elegance of Telugu womanhood. Calendar art and Telugu cinema poster illustration quality.", Category = "Regional", IconEmoji = "\u270D\uFE0F", AccentColor = "#E91E63", IsActive = true, SortOrder = 47 },

            // ── Indian Mythological Styles (8 — from different Puranas) ──

            // 1. Vishnu Purana — Lord Vishnu divine form
            new StylePreset { Id = 200, Name = "Vishnu Divine", Description = "Lord Vishnu cosmic preserver from Vishnu Purana", PromptTemplate = "Transform the subject into Lord Vishnu, the cosmic preserver from the Vishnu Purana. CRITICAL: Preserve the subject's exact facial features and identity. Render with radiant blue skin tone. Adorned with an elaborate golden Kiritam (towering crown) studded with rubies and emeralds. Four divine arms holding the Sudarshana Chakra (flaming discus), Panchajanya Shankha (sacred conch), Kaumodaki Gada (golden mace), and a blooming Padma (lotus). Wearing lustrous yellow Pitambara silk dhoti with golden border. Chest adorned with the Kaustubha gem and Vanamala (forest garland reaching the knees). Ornate gold armlets, wristlets, and anklets. Serene all-knowing compassionate expression. Background of Vaikuntha — celestial palace with cosmic ocean (Kshira Sagara), Shesha Naga (divine serpent throne), and golden pillared mandapam. Divine aura with golden light rays emanating outward. Classical Indian devotional calendar art quality with rich saturated colors.", Category = "Mythological", IconEmoji = "\U0001F539", AccentColor = "#1565C0", IsActive = true, SortOrder = 50 },

            // 2. Shiva Purana — Lord Shiva Nataraja cosmic dancer
            new StylePreset { Id = 201, Name = "Shiva Nataraja", Description = "Lord Shiva cosmic dancer from Shiva Purana", PromptTemplate = "Transform the subject into Lord Shiva Nataraja, the cosmic dancer from the Shiva Purana. CRITICAL: Preserve the subject's exact facial features and identity. Render with ash-smeared fair skin with a third eye (Trinetra) glowing on the forehead. Matted jata (dreadlocked hair) flowing upward with the crescent moon (Chandrama) nestled within, the holy river Ganga cascading from the locks. Coiled serpent Vasuki around the neck. Wearing a tiger skin around the waist and rudraksha mala. Dynamic Tandava dance pose within a blazing Prabha Mandala (cosmic ring of fire) symbolizing the cycle of creation and destruction. Upper right hand holding the Damaru (drum of creation), upper left hand holding Agni (sacred fire). Lower right hand in Abhaya mudra (fear not gesture), lower left pointing to the raised foot granting liberation. Trampling the dwarf Apasmara (ignorance) underfoot. Background of Mount Kailash with snow peaks, cosmic nebulae, and starfields. Dramatic divine lighting with blue and gold tones. Sacred magnificent temple sculpture brought to life.", Category = "Mythological", IconEmoji = "\U0001F525", AccentColor = "#4527A0", IsActive = true, SortOrder = 51 },

            // 3. Markandeya Purana (Devi Mahatmya) — Goddess Durga
            new StylePreset { Id = 202, Name = "Durga Shakti", Description = "Goddess Durga warrior from Markandeya Purana", PromptTemplate = "Transform the subject into Goddess Durga Mahishasuramardini, the invincible warrior goddess from the Devi Mahatmya of the Markandeya Purana. CRITICAL: Preserve the subject's exact facial features and identity. Render with luminous golden skin radiating divine Shakti energy. Eight powerful arms wielding divine weapons — Trishul (trident) from Shiva, Sudarshana Chakra from Vishnu, bow and arrows from Vayu, thunderbolt from Indra, sword and shield, and a lotus. Wearing a magnificent red and gold silk saree with ornate temple jewelry — heavy gold necklace, elaborate crown, armlets, and nose ring. Fierce yet compassionate expression with blazing eyes of righteous anger. Riding the majestic lion (Simha Vahana) in a powerful stance. Background of an epic battlefield with dramatic stormy skies, divine light breaking through dark clouds, and celestial beings showering flowers from above. Rich red, gold, and saffron color palette. Bengal Durga Puja pandal art quality with dramatic cinematic lighting.", Category = "Mythological", IconEmoji = "\u2694\uFE0F", AccentColor = "#C62828", IsActive = true, SortOrder = 52 },

            // 4. Bhagavata Purana — Lord Krishna
            new StylePreset { Id = 203, Name = "Krishna Murali", Description = "Lord Krishna the divine flutist from Bhagavata Purana", PromptTemplate = "Transform the subject into Lord Krishna, the enchanting divine flutist from the Bhagavata Purana. CRITICAL: Preserve the subject's exact facial features and identity. Render with beautiful dark blue (Megha Shyam) skin complexion glowing with inner divine light. Adorned with a magnificent Peacock feather crown (Mor Mukut) with jewels. Playing the enchanting Murali (bamboo flute) with graceful fingers. Wearing lustrous yellow Pitambara silk dhoti and uttariya (upper cloth). Ornate gold Makara Kundala (crocodile-shaped earrings), Vaijayanti Mala (five-gem garland), gold armlets, and anklets with tiny bells. Gentle mischievous smile (Manda Hasa). Tribhanga (three-bend) graceful standing pose. Background of enchanted Vrindavan — lush Kadamba trees along the banks of the sacred Yamuna river, cows grazing peacefully, lotus ponds, full moon night with soft silver light. Fireflies and flower petals floating in the air. Classical Indian miniature painting quality with Pichwai and Rajasthani art influences. Warm golden divine illumination.", Category = "Mythological", IconEmoji = "\U0001F99A", AccentColor = "#0D47A1", IsActive = true, SortOrder = 53 },

            // 5. Padma Purana / Valmiki Ramayana — Lord Rama
            new StylePreset { Id = 204, Name = "Rama Maryada", Description = "Lord Rama the noble warrior-king from Padma Purana", PromptTemplate = "Transform the subject into Lord Rama, Maryada Purushottam — the supreme ideal man from the Padma Purana and Ramayana. CRITICAL: Preserve the subject's exact facial features and identity. Render with a noble dark green-blue complexion radiating dharmic righteousness. Regal yet humble expression of a warrior-prince. Adorned with a golden Mukuta (crown) set with precious stones. Wielding the mighty Kodanda (divine bow) with a quiver of celestial arrows on the back. Wearing royal green and gold silk Vanavasi attire — dhoti, angavastra with forest-style ornaments combining royal elegance with ascetic simplicity. Gold armlets (Keyura), sacred thread, and Tilaka on the forehead. Strong athletic build with a commanding noble posture. Background of the majestic forests of Dandakaranya — towering ancient trees, sacred rivers, golden sunlight filtering through the canopy, with distant view of a grand palatial Ayodhya silhouette. A subtle divine golden halo behind the head. Classical Tanjore and Mysore painting fusion style with rich greens, golds, and earth tones. Devotional calendar art masterpiece quality.", Category = "Mythological", IconEmoji = "\U0001F3F9", AccentColor = "#2E7D32", IsActive = true, SortOrder = 54 },

            // 6. Ganesha Purana — Lord Ganesha
            new StylePreset { Id = 205, Name = "Ganesha Vighnaharta", Description = "Lord Ganesha the remover of obstacles from Ganesha Purana", PromptTemplate = "Transform the subject into a devotional portrait inspired by Lord Ganesha, Vighnaharta — the remover of obstacles from the Ganesha Purana. CRITICAL: Preserve the subject's exact facial features and identity. Render the subject seated on a magnificent golden Simhasana (throne) in a regal divine pose. Adorned with an elaborate golden Mukuta (crown) studded with rubies and diamonds. Wearing rich red and gold silk dhoti with ornate waistband. Heavy gold temple jewelry — necklaces, armlets, sacred thread (Yajnopavita) across the chest. Holding Modaka (sweet dumpling) in one hand, lotus in another, and displaying Abhaya Mudra (blessing gesture). A broken tusk held gracefully. Surrounded by divine attributes — Mushika (mouse vehicle) at the feet, plates of sweets and fruits as offerings. Background of an opulent temple sanctum with carved pillars, oil lamps (diyas) casting warm golden light, flower garlands, and incense smoke curling upward. Rich palette of vermillion red, turmeric gold, and sacred saffron. Festive Ganesh Chaturthi celebration art quality with divine radiance.", Category = "Mythological", IconEmoji = "\U0001FAB7", AccentColor = "#E65100", IsActive = true, SortOrder = 55 },

            // 7. Sundara Kanda / Shiva Purana — Lord Hanuman
            new StylePreset { Id = 206, Name = "Hanuman Bajrang", Description = "Lord Hanuman the mighty devotee from Shiva Purana", PromptTemplate = "Transform the subject into Lord Hanuman, Bajrang Bali — the mighty devotee warrior from the Shiva Purana and Sundara Kanda. CRITICAL: Preserve the subject's exact facial features and identity. Render with a powerful muscular warrior physique and glowing vermillion-orange (sindoor) skin. Heroic fierce devotional expression with blazing determined eyes. Wearing a golden crown (Mukut) and golden armour chest plate. Adorned with gold armlets, wristlets, and a sacred thread. A flowing long tail curling upward with divine energy. Wielding the colossal golden Gada (mace) in one mighty hand. Wearing a short dhoti and carrying the Sanjeevani mountain in the other hand (showing his legendary feat of carrying the entire mountain to save Lakshmana). Open chest revealing the image of Lord Rama and Sita within his heart — the ultimate symbol of devotion. Background of a dramatic sky — flying through clouds at sunset with Lanka burning far below, epic Ramayana battlefield with divine armies. Intense warm palette of saffron, gold, vermillion, and crimson. Dramatic heroic lighting with divine glow. Powerful Indian mythological calendar art quality.", Category = "Mythological", IconEmoji = "\U0001F4AA", AccentColor = "#FF6F00", IsActive = true, SortOrder = 56 },

            // 8. Brahmanda Purana — Goddess Saraswati
            new StylePreset { Id = 207, Name = "Saraswati Vidya", Description = "Goddess Saraswati the divine muse from Brahmanda Purana", PromptTemplate = "Transform the subject into Goddess Saraswati, Vidya Dayini — the divine goddess of knowledge, music, and wisdom from the Brahmanda Purana. CRITICAL: Preserve the subject's exact facial features and identity. Render with luminous fair radiant skin glowing with the pure white light of knowledge. Wearing an elegant pristine white silk saree with subtle silver and gold threadwork (representing purity and Sattva). Adorned with delicate pearl and diamond jewelry — simple yet divine. Four graceful arms — playing the sacred Veena (stringed instrument) with two hands, holding the Pustaka (sacred scriptures) in one hand and a Sphatika Mala (crystal rosary) in another. Seated gracefully on a blooming white Padma (lotus) in Padmasana. A regal yet gentle serene expression of supreme wisdom. The sacred swan (Hamsa Vahana) at her side. Background of a serene sacred riverbank at dawn — the Saraswati river with lotus ponds, ancient Banyan trees, and a soft saffron-pink sunrise sky. White cranes, floating lotus petals, and gentle mist on the waters. Soft ethereal lighting with white, gold, and pale blue tones. Vasant Panchami devotional art quality. Classical Indian painting masterpiece.", Category = "Mythological", IconEmoji = "\U0001F3B6", AccentColor = "#F5F5F5", IsActive = true, SortOrder = 57 },

            // ── Super Heroes (14) ──
            new StylePreset { Id = 300, Name = "Superman Style", Description = "Kryptonian hero with cape and shield emblem", PromptTemplate = "Transform the subject into a powerful Kryptonian superhero. CRITICAL: Preserve the subject's exact facial features and identity. Render wearing an iconic blue bodysuit with a bold red and yellow shield emblem on the chest. Flowing crimson red cape billowing heroically in the wind. Red boots and belt. Strong muscular physique in a confident heroic pose — fists on hips or one arm raised in flight. Chiseled jawline with a confident determined expression. Perfectly styled dark hair with a single iconic curl on the forehead. Background of a metropolitan cityscape — soaring skyscrapers, blue sky with sunlight breaking through clouds. Flying above the city or landing with dramatic impact. Warm primary color palette of blue, red, and yellow. Dynamic comic book art quality with cinematic lighting.", Category = "Super Heroes", IconEmoji = "\U0001F9B8", AccentColor = "#1565C0", IsActive = true, SortOrder = 60 },
            new StylePreset { Id = 301, Name = "Batman Style", Description = "Dark Knight gothic vigilante hero", PromptTemplate = "Transform the subject into a dark vigilante knight detective. CRITICAL: Preserve the subject's exact facial features and identity. Render wearing a dark grey and black armored tactical suit with a bat-shaped emblem on the chest. Pointed-ear cowl revealing only the lower face with a strong jawline. Long flowing dark cape with scalloped bat-wing edges. Utility belt loaded with gadgets. Muscular athletic build in a brooding intense stance — perched on a gargoyle or standing on a rooftop. Background of a dark gothic city at night — rain-slicked streets, Art Deco architecture, searchlight beam cutting through fog, full moon. Dark noir color palette of deep blacks, greys, and midnight blue with occasional amber light. Dramatic cinematic comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F987", AccentColor = "#212121", IsActive = true, SortOrder = 61 },
            new StylePreset { Id = 302, Name = "Wonder Woman Style", Description = "Amazonian warrior princess of Themyscira", PromptTemplate = "Transform the subject into an Amazonian warrior princess. CRITICAL: Preserve the subject's exact facial features and identity. Render wearing golden and crimson Amazonian battle armor — a tiara crown with a red star, gleaming metallic breastplate in gold and red, armored skirt with blue starfield accents. Indestructible silver bracelets on both wrists. Wielding a glowing golden lasso. A sword and shield nearby. Flowing dark hair with a regal yet fierce expression. Powerful athletic stance ready for battle. Background of paradise island Themyscira — ancient Greek marble temples, turquoise Mediterranean waters, and lush green cliffs. Warm golden sunlight. Majestic, powerful, and graceful. Cinematic action comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F478", AccentColor = "#C62828", IsActive = true, SortOrder = 62 },
            new StylePreset { Id = 303, Name = "Spider-Man Style", Description = "Agile web-slinging acrobatic hero", PromptTemplate = "Transform the subject into an agile web-slinging superhero. CRITICAL: Preserve the subject's exact facial features and identity — render in a half-mask style where the lower face is visible. Wearing a sleek red and blue bodysuit with intricate black web patterns across the red sections. Large white angular eye lenses on the mask with expressive shape. A black spider emblem on the chest. Dynamic acrobatic pose — swinging between skyscrapers on a web line, mid-flip, or crouching on a wall. Lean athletic build. Background of a vibrant New York City — towering glass skyscrapers, busy streets far below, sunset golden hour light. Web lines glistening in sunlight. Energetic dynamic perspective with motion blur. Vibrant red, blue, and gold comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F577\uFE0F", AccentColor = "#D32F2F", IsActive = true, SortOrder = 63 },
            new StylePreset { Id = 304, Name = "Iron Man Style", Description = "High-tech armored genius superhero", PromptTemplate = "Transform the subject into a high-tech armored genius superhero. CRITICAL: Preserve the subject's exact facial features and identity — render with the helmet visor open revealing the face, or in a HUD holographic overlay. Wearing a sleek red and gold powered armor suit with glowing blue Arc Reactor on the chest. Repulsor beams glowing in the palms. Intricate mechanical panel lines and gold trim across the armor. Confident stance — one arm raised with repulsor charging, or landing in a three-point hero pose. Background of a futuristic tech laboratory with holographic displays, or flying through clouds at supersonic speed with jet trail. Metallic reflections and volumetric lighting. High-tech red, gold, and blue color palette with neon glow effects. Cinematic sci-fi quality.", Category = "Super Heroes", IconEmoji = "\U0001F916", AccentColor = "#F44336", IsActive = true, SortOrder = 64 },
            new StylePreset { Id = 305, Name = "Captain America Style", Description = "Patriotic super-soldier with vibranium shield", PromptTemplate = "Transform the subject into a patriotic super-soldier hero. CRITICAL: Preserve the subject's exact facial features and identity. Render wearing a blue tactical stealth suit with white star emblem on the chest. Red and white stripe accent details. A winged helmet or headpiece. Carrying the iconic circular vibranium shield — concentric rings of red, white, and blue with a central star. Peak-human muscular physique with a noble commanding stance. Determined righteous expression of leadership. Background of a battlefield — dramatic smoke, allies rallying behind. American flag colors reflected in the scene. Strong patriotic lighting — golden hour with dramatic cloud formations. Bold heroic primary color palette. Classic military propaganda poster meets cinematic comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F6E1\uFE0F", AccentColor = "#1976D2", IsActive = true, SortOrder = 65 },
            new StylePreset { Id = 306, Name = "Thor Style", Description = "Norse god of thunder with Mjolnir hammer", PromptTemplate = "Transform the subject into a mighty Norse god of thunder. CRITICAL: Preserve the subject's exact facial features and identity. Render with long flowing blonde hair and a neatly trimmed beard. Wearing ornate Asgardian battle armor — dark leather and silver metallic plates with Norse rune engravings. A flowing crimson red cape fastened with circular Norse disc brooches. Wielding an enchanted hammer crackling with blue-white lightning. Powerful godlike muscular physique in a battle-ready stance. Lightning bolts arcing from the weapon and through the sky. Background of the Rainbow Bridge Bifrost with golden spires of Asgard, cosmic nebulae, and dramatic thunderstorm clouds. Electric blue, silver, and red color palette. Epic mythological cinematic quality.", Category = "Super Heroes", IconEmoji = "\u26A1", AccentColor = "#4527A0", IsActive = true, SortOrder = 66 },
            new StylePreset { Id = 307, Name = "Black Panther Style", Description = "Wakandan vibranium warrior king", PromptTemplate = "Transform the subject into a vibranium-powered Wakandan warrior king. CRITICAL: Preserve the subject's exact facial features and identity — render with the ceremonial necklace that forms the suit, face visible. Wearing a sleek black vibranium nanotech suit with subtle purple kinetic energy patterns pulsing across the surface. Silver vibranium claws extended from the fingertips. A ceremonial tooth necklace. Regal powerful stance combining royal dignity with warrior readiness. Background of the technologically advanced hidden nation of Wakanda — futuristic afro-futurist cityscape with vibranium-powered trains, lush African jungle, a great panther statue carved into a cliff face. Purple, black, and silver color palette with neon vibranium glow. Afro-futurist cinematic art quality.", Category = "Super Heroes", IconEmoji = "\U0001F406", AccentColor = "#6A1B9A", IsActive = true, SortOrder = 67 },
            new StylePreset { Id = 308, Name = "Wolverine Style", Description = "Adamantium-clawed feral mutant warrior", PromptTemplate = "Transform the subject into a feral adamantium-clawed mutant warrior. CRITICAL: Preserve the subject's exact facial features and identity. Render with wild, swept-back dark hair in distinctive pointed sideburns style. Wearing the classic yellow and blue spandex suit with a black tiger-stripe pattern, or rugged leather jacket with dog tags. Three razor-sharp adamantium claws extending from each fist, gleaming metallic. Muscular compact powerful build with a fierce snarling expression showing intensity and rage. Aggressive battle-ready stance. Background of a dark forest or Canadian wilderness under a full moon, dramatic slashing claw marks in the environment. Dark intense color palette with metallic silver highlights. Gritty raw comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F43A", AccentColor = "#F9A825", IsActive = true, SortOrder = 68 },
            new StylePreset { Id = 309, Name = "The Flash Style", Description = "Lightning-fast Speed Force speedster hero", PromptTemplate = "Transform the subject into a lightning-fast speedster hero. CRITICAL: Preserve the subject's exact facial features and identity — render with the cowl pulled back or lower face exposed. Wearing a sleek scarlet red bodysuit with golden lightning bolt emblem on the chest. Gold boots and gold winged ear pieces. Speed Force lightning crackling in yellow and orange trails around the entire body. Dynamic speed-running pose with afterimage motion trails. Background of a city street turned into a blur of streaking lights — everything frozen in time while the speedster moves. Speed Force energy vortex with lightning. Red, gold, and electric yellow color palette. High-speed dynamic comic book art quality.", Category = "Super Heroes", IconEmoji = "\u26A1", AccentColor = "#E65100", IsActive = true, SortOrder = 69 },
            new StylePreset { Id = 310, Name = "Aquaman Style", Description = "Powerful Atlantean ocean king with trident", PromptTemplate = "Transform the subject into a powerful Atlantean ocean king. CRITICAL: Preserve the subject's exact facial features and identity. Render with long flowing hair and a beard, muscular warrior build. Wearing golden scale armor on the upper body — thousands of tiny metallic fish-scale plates gleaming. Green leggings and gauntlets with Atlantean tribal markings. Wielding a legendary golden trident crackling with ocean energy. A majestic regal yet fierce expression. Background of the underwater kingdom of Atlantis — bioluminescent coral architecture, schools of exotic fish, ancient stone ruins, shafts of sunlight filtering through deep ocean water. Underwater caustic light effects. Ocean teal, gold, and deep blue color palette. Epic underwater cinematic art quality.", Category = "Super Heroes", IconEmoji = "\U0001F531", AccentColor = "#00838F", IsActive = true, SortOrder = 70 },
            new StylePreset { Id = 311, Name = "Doctor Strange Style", Description = "Master of mystic arts sorcerer supreme", PromptTemplate = "Transform the subject into a master of the mystic arts sorcerer. CRITICAL: Preserve the subject's exact facial features and identity. Render with distinguished goatee and mustache. Wearing an ornate blue tunic with golden sash, and the iconic crimson Cloak of Levitation with a high collar flowing dramatically. A glowing green amulet on the chest. Conjuring intricate golden mandala shields and spell circles — geometric sacred geometry patterns made of glowing orange-gold energy from the hands. Background of a mystical Victorian library filled with ancient artifacts, floating books, and interdimensional portals. Mandelbrot fractal dimensions folding. Purple, gold, orange, and cosmic blue color palette. Mystical psychedelic cinematic art quality.", Category = "Super Heroes", IconEmoji = "\U0001F52E", AccentColor = "#7B1FA2", IsActive = true, SortOrder = 71 },
            new StylePreset { Id = 312, Name = "Green Lantern Style", Description = "Emerald willpower cosmic ring-bearer", PromptTemplate = "Transform the subject into an emerald willpower-powered cosmic hero. CRITICAL: Preserve the subject's exact facial features and identity. Wearing a sleek green and black bodysuit with the Green Lantern Corps emblem — a glowing green lantern symbol on the chest. A domino mask in green. The Power Ring on one hand glowing with intense emerald green energy. Conjuring a massive green energy construct — a giant fist, shield, or weapon — formed from pure willpower. Background of deep outer space — cosmic nebulae, distant galaxies, a green-glowing planet in the distance. Other Lanterns visible as green streaks of light. Green and black color palette with intense emerald glow effects. Cosmic sci-fi comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F49A", AccentColor = "#2E7D32", IsActive = true, SortOrder = 72 },
            new StylePreset { Id = 313, Name = "Deadpool Style", Description = "Fourth-wall-breaking anti-hero mercenary", PromptTemplate = "Transform the subject into a wisecracking anti-hero mercenary. CRITICAL: Preserve the subject's exact facial features and identity — render with the mask pulled up above the nose, or with a split-view showing half-mask half-face. Wearing a full red and black tactical suit with katana swords strapped in an X-pattern on the back. Utility belt loaded with pouches, guns, and grenades. White eye patches on the red mask with exaggerated expressive shapes. Breaking the fourth wall — pointing directly at the viewer with a finger gun, or holding a speech bubble. Dynamic irreverent pose. Background of explosive chaos — buildings crumbling, comedic graffiti, pop-culture references scattered around. Red, black, and white color palette with comic splatter effects. Irreverent comedic comic book art quality.", Category = "Super Heroes", IconEmoji = "\U0001F480", AccentColor = "#B71C1C", IsActive = true, SortOrder = 73 },

            // ── Cartoon Characters (14) ──
            new StylePreset { Id = 320, Name = "Mickey Mouse Style", Description = "Classic Disney round-ear animation", PromptTemplate = "Transform the subject into classic Disney animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the iconic 1930s-1940s Walt Disney animation style — perfectly round head with large circular black ears, big expressive oval eyes with white highlights, a wide cheerful smile with a button nose. Clean smooth animation lines. Wearing classic red shorts with two white buttons and large yellow shoes. White gloves on hands. Joyful exuberant expression with one arm waving. Background of a colorful Disney theme park or a magical castle with fireworks. Bright primary colors — red, yellow, black, and white. Classic hand-drawn cel animation quality with clean ink outlines and flat vibrant colors.", Category = "Cartoon Characters", IconEmoji = "\U0001F42D", AccentColor = "#E53935", IsActive = true, SortOrder = 80 },
            new StylePreset { Id = 321, Name = "Bugs Bunny Style", Description = "Classic Looney Tunes wise-cracking cartoon", PromptTemplate = "Transform the subject into classic Looney Tunes animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the iconic Warner Bros Looney Tunes style — large expressive eyes with a sly mischievous smirk. Exaggerated cartoon proportions with smooth fluid animation lines. Long grey rabbit ears, white cheeks and belly, big flat feet. Casually leaning against something while munching a carrot with a too-cool attitude. One eyebrow raised with a knowing expression. Background of a colorful cartoon landscape — desert mesas, rabbit holes, or a theatrical red curtain stage. Classic Tex Avery / Chuck Jones animation style. Vibrant saturated colors with bold black outlines. Vintage hand-drawn cel animation quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F430", AccentColor = "#FF8F00", IsActive = true, SortOrder = 81 },
            new StylePreset { Id = 322, Name = "SpongeBob Style", Description = "Nickelodeon Bikini Bottom undersea cartoon", PromptTemplate = "Transform the subject into Nickelodeon SpongeBob SquarePants animation style. CRITICAL: Preserve the subject's facial likeness and identity mapped onto a cartoon character form. Render in the distinctive flat 2D SpongeBob style — bright optimistic blocky character design with enormous blue eyes, a gap-toothed enthusiastic grin, and rosy cheeks. Wearing the iconic white shirt, brown pants, and red tie. Square-shaped body proportions. Tiny limbs with exaggerated poses of excitement. Background of the colorful underwater Bikini Bottom — pineapple house, jellyfish fields, the Krusty Krab, coral and tropical fish. Bright cheerful color palette — yellow, blue, pink, and green. Flat cartoon illustration quality with bold outlines.", Category = "Cartoon Characters", IconEmoji = "\U0001F9FD", AccentColor = "#FDD835", IsActive = true, SortOrder = 82 },
            new StylePreset { Id = 323, Name = "Tom & Jerry Style", Description = "Classic Hanna-Barbera chase cartoon", PromptTemplate = "Transform the subject into classic Hanna-Barbera Tom & Jerry animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the golden-age MGM cartoon style of the 1940s-1950s — fluid expressive animation with soft rounded character designs. Exaggerated slapstick expressions — wide eyes of surprise, stretched limbs, speed lines. Dynamic chase-scene action pose with one character mid-run and another mid-pounce. Rich watercolor-painted backgrounds — a warm homey 1950s kitchen or living room with detailed furniture. Classic cartoon sound-effect elements — stars from impact, sweat drops, motion lines. Warm nostalgic color palette. Vintage hand-painted cel animation quality with painterly backgrounds.", Category = "Cartoon Characters", IconEmoji = "\U0001F431", AccentColor = "#5D4037", IsActive = true, SortOrder = 83 },
            new StylePreset { Id = 324, Name = "Scooby-Doo Style", Description = "Mystery-solving groovy retro cartoon", PromptTemplate = "Transform the subject into classic Hanna-Barbera Scooby-Doo animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the distinctive 1969 Scooby-Doo character design — bold simplified shapes with heavy dark outlines. Retro 1970s color palette with warm browns, oranges, and avocado greens. Slightly scared but brave expression. Holding a flashlight in a dark spooky hallway. Background of a haunted mansion — cobwebs, creaky doors, ghostly shadows, old portraits with moving eyes, foggy graveyard outside. Classic mystery-solving detective aesthetic. The Mystery Machine van visible through a window. Vintage Saturday morning cartoon quality with flat cel-shaded colors and groovy retro vibes.", Category = "Cartoon Characters", IconEmoji = "\U0001F415", AccentColor = "#6D4C41", IsActive = true, SortOrder = 84 },
            new StylePreset { Id = 325, Name = "Simpsons Style", Description = "Yellow Springfield TV cartoon style", PromptTemplate = "Transform the subject into The Simpsons animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the iconic Matt Groening Springfield style — bright yellow skin, large round bulging eyes with circular pupils, prominent overbite with visible teeth. Simplified cartoon body proportions with four-fingered hands. Bold clean black outlines with flat bright colors. Distinctive spiky or rounded hair silhouette. Casual everyday clothing. Background of iconic Springfield — the Simpsons house, Kwik-E-Mart, Springfield Nuclear Power Plant, or Moe's Tavern. Signature Simpsons pastel color palette — yellow, blue, orange, and pink. Clean flat vector-like cel animation quality. Perfect Matt Groening character design.", Category = "Cartoon Characters", IconEmoji = "\U0001F49B", AccentColor = "#FBC02D", IsActive = true, SortOrder = 85 },
            new StylePreset { Id = 326, Name = "Pokemon Trainer Style", Description = "Pokemon anime creature-trainer adventure", PromptTemplate = "Transform the subject into a Pokemon anime character style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the colorful Pokemon anime style — large sparkling expressive eyes, spiky dynamic hair with vibrant highlights. Wearing a Pokemon Trainer outfit — a cap with a Pokeball logo, a jacket with bold color blocking, fingerless gloves, and a belt with six Pokeball holders. Confident adventure-ready pose with one arm extended holding a glowing Pokeball. A Pikachu companion with rosy cheeks and lightning tail on the shoulder. Background of a vibrant Pokemon world — lush Route with tall grass, wild Pokemon silhouettes, a Pokemon Center in the distance. Bright cheerful anime color palette. Professional Pokemon anime art quality.", Category = "Cartoon Characters", IconEmoji = "\u26A1", AccentColor = "#F44336", IsActive = true, SortOrder = 86 },
            new StylePreset { Id = 327, Name = "Doraemon Style", Description = "Japanese robotic cat gadget cartoon", PromptTemplate = "Transform the subject into Doraemon Japanese animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the distinctive Fujiko F. Fujio manga/anime style — rounded soft character design with large expressive oval eyes. Clean simple linework with gentle pastel coloring. Friendly warm expression with rosy cheeks. Wearing school uniform or casual Japanese clothing. Standing next to the iconic blue robotic cat companion with bell collar and 4D pocket. Reaching into the magical pocket pulling out a fantastic gadget. Background of a typical Japanese suburban neighborhood — house, a grassy vacant lot where friends play, cherry blossom trees. Soft pastel blue, pink, and yellow palette. Warm wholesome Japanese children's anime quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F514", AccentColor = "#1E88E5", IsActive = true, SortOrder = 87 },
            new StylePreset { Id = 328, Name = "Shin-chan Style", Description = "Mischievous Japanese kid cartoon comedy", PromptTemplate = "Transform the subject into Crayon Shin-chan animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the distinctive Yoshito Usui manga style — thick bold outlines, extremely simplified character design. Tiny dot eyes set wide apart, a mischievous smirking mouth, and prominent thick eyebrows. Compact stumpy body proportions with a big head. Cheeky naughty expression — sticking tongue out or doing a silly dance. Wearing a simple T-shirt and shorts. Background of a typical messy Japanese suburban home or kindergarten classroom. Bright bold flat colors — red, yellow, blue. Simple clean Japanese cartoon style with charming childlike simplicity. Comedy manga illustration quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F61C", AccentColor = "#FF7043", IsActive = true, SortOrder = 88 },
            new StylePreset { Id = 329, Name = "Ben 10 Style", Description = "Alien hero Omnitrix transformation", PromptTemplate = "Transform the subject into Cartoon Network Ben 10 animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in bold angular character shapes with sharp dynamic lines. Wearing a white T-shirt with a black stripe, cargo pants, and sneakers. The iconic Omnitrix watch on the wrist — a green and black alien device glowing with emerald energy. Mid-transformation pose — one arm morphing with green flash energy, alien DNA patterns swirling. Confident adventurous expression of a young hero. Background of an alien-tech landscape — crashed spacecraft, desert canyon, or futuristic base with holographic alien displays. Green, black, and white color palette with alien glow effects. Dynamic action cartoon quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F47D", AccentColor = "#43A047", IsActive = true, SortOrder = 89 },
            new StylePreset { Id = 330, Name = "Powerpuff Girls Style", Description = "Sugar, spice, and everything nice superhero", PromptTemplate = "Transform the subject into Cartoon Network Powerpuff Girls animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in Craig McCracken's iconic style — extremely simplified and adorable character design with an enormous round head, giant sparkly eyes taking up most of the face, tiny body with stubby limbs. Bright colorful outfit. Flying through the air leaving a colored energy streak trail. Cute yet powerful determined expression. Background of the colorful retro-futuristic city of Townsville — candy-colored buildings, blue sky, the hotline telephone, or a laboratory with Chemical X. Bright pastel candy color palette — pink, blue, green, and purple. Bold graphic flat cartoon style with thick outlines. Adorable yet action-packed quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F496", AccentColor = "#EC407A", IsActive = true, SortOrder = 90 },
            new StylePreset { Id = 331, Name = "Dexters Lab Style", Description = "Boy genius secret laboratory cartoon", PromptTemplate = "Transform the subject into Cartoon Network Dexter's Laboratory animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in Genndy Tartakovsky's distinctive angular style — exaggerated proportions with a small body and large head. Wearing a white lab coat, purple latex gloves, and black boots. Round glasses perched on the nose. A genius inventor expression — intense focused concentration. Standing in an enormous secret underground laboratory filled with impossible machines — bubbling beakers, Tesla coils sparking, giant computer screens, robotic arms, and flashing control panels. Bold geometric angular character design. Bright saturated color palette — purple, blue, green, and chrome silver. Retro-futuristic Cartoon Network animation quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F52C", AccentColor = "#7B1FA2", IsActive = true, SortOrder = 91 },
            new StylePreset { Id = 332, Name = "Johnny Bravo Style", Description = "Muscular retro cool-dude cartoon", PromptTemplate = "Transform the subject into Cartoon Network Johnny Bravo animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in the iconic Van Partible style — massively exaggerated proportions with an enormous muscular upper body (huge chest and biceps) tapering to impossibly tiny legs. Towering blonde pompadour hairstyle. Wearing a fitted black T-shirt and blue jeans with a large belt buckle. Black sunglasses always on. Flexing muscles in a confident overconfident pose — pointing at the viewer, flexing biceps, or striking a karate stance. Background of a sunny suburban neighborhood, a gym, or a beach with palm trees. Bold retro pop-art inspired color palette — black, blue, and sun-yellow. 1990s Cartoon Network animation quality with thick bold outlines.", Category = "Cartoon Characters", IconEmoji = "\U0001F4AA", AccentColor = "#FFD600", IsActive = true, SortOrder = 92 },
            new StylePreset { Id = 333, Name = "Adventure Time Style", Description = "Whimsical candy kingdom adventure cartoon", PromptTemplate = "Transform the subject into Cartoon Network Adventure Time animation style. CRITICAL: Preserve the subject's facial likeness and identity. Render in Pendleton Ward's distinctive whimsical style — soft rounded noodle-arm character design with simple dot eyes and a wide expressive mouth. Clean minimal linework with flat pastel colors. Wearing a fun adventurer outfit — a bear-eared hat or backpack with a sword. A cute dog companion stretching and shape-shifting nearby. Background of the magical Land of Ooo — Candy Kingdom with pastel buildings, the Ice King mountain, Tree Fort house, rolling green hills with strange creatures. Psychedelic sunset sky with cotton-candy clouds. Pastel rainbow color palette — light blue, pink, yellow, and mint green. Whimsical hand-drawn indie animation quality.", Category = "Cartoon Characters", IconEmoji = "\U0001F5E1\uFE0F", AccentColor = "#4FC3F7", IsActive = true, SortOrder = 93 },

