            new StylePreset { Id = 340, Name = "Cyberpunk Edgerunner", Description = "Neon cyberpunk anime mercenary style", PromptTemplate = "Transform the subject into a cyberpunk anime edgerunner mercenary. CRITICAL: Preserve the subject's exact facial features and identity. Render in vivid anime style — sharp dynamic lines, intense expressions, and exaggerated action poses. Cybernetic augmentations visible — glowing circuit lines under the skin, a chrome cyberarm, optical implants with HUD display in the eyes. Wearing a punk-tech jacket with neon LED trim, tactical vest, and combat boots. Dual-wielding futuristic pistols. Background of a rain-soaked Night City at night — towering megabuildings with holographic advertisements, neon signs in pink and cyan, flying cars. Neon pink, cyan, chrome, and deep purple color palette. Cyberpunk anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F306", AccentColor = "#E040FB", IsActive = true, SortOrder = 100 },
            new StylePreset { Id = 341, Name = "Pirate King Style", Description = "Grand Line pirate captain adventure anime", PromptTemplate = "Transform the subject into a Grand Line pirate captain in One Piece anime style. CRITICAL: Preserve the subject's exact facial features and identity. Render in Eiichiro Oda's distinctive manga style — bold expressive features, dynamic exaggerated proportions, and infectious grin of adventure. Wearing a straw hat with a red band, an open red vest revealing a muscular chest, blue shorts, and sandals. A pirate flag with skull and crossbones flying in the background. Confident captain pose on the bow of a pirate ship — one foot on the railing, fist raised to the sky. Background of the vast Grand Line ocean — massive waves, a pirate ship, distant mysterious islands. Vibrant saturated color palette — warm reds, blues, and ocean teal. One Piece manga/anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F3F4\u200D\u2620\uFE0F", AccentColor = "#D32F2F", IsActive = true, SortOrder = 101 },
            new StylePreset { Id = 342, Name = "Saiyan Warrior Style", Description = "Super powered energy warrior anime", PromptTemplate = "Transform the subject into a powerful Saiyan warrior in Dragon Ball Z anime style. CRITICAL: Preserve the subject's exact facial features and identity. Render in Akira Toriyama's iconic style — bold clean lines, sharp angular features, and intense determined expression. Hair transformed into Super Saiyan form — spiky golden blonde hair standing straight up, radiating golden ki energy aura. Eyes turned fierce teal green. Wearing Saiyan battle armor — blue bodysuit with white and gold chest plate, white gloves and boots. Powering up in a battle stance — fists clenched, ki energy crackling, ground cracking beneath. Background of a barren rocky battlefield — craters, shattered mountains, dramatic sky with energy beams. Intense gold, blue, and white color palette. Dragon Ball Z anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F525", AccentColor = "#FFD600", IsActive = true, SortOrder = 102 },
            new StylePreset { Id = 343, Name = "Demon Slayer Hashira", Description = "Breathing technique samurai swordsman", PromptTemplate = "Transform the subject into a Hashira-rank demon slayer swordsman. CRITICAL: Preserve the subject's exact facial features and identity. Render in Ufotable's stunning anime style — crisp detailed linework with vivid coloring and dramatic shading. Wearing the Demon Slayer Corps uniform — black gakuran jacket with a white belt, and a distinctive haori with unique geometric or floral design. Gripping a blade that changes color with breathing technique — the blade edge glowing with elemental energy. Performing a Breathing Form technique — dynamic slash pose with swirling elemental effects (water dragons, flame trails, or lightning arcs). Background of a moonlit bamboo forest with wisteria flowers. Rich saturated color palette with glowing technique effects. Ufotable-quality cinematic anime art.", Category = "Anime & Gaming", IconEmoji = "\u2694\uFE0F", AccentColor = "#7B1FA2", IsActive = true, SortOrder = 103 },
            new StylePreset { Id = 344, Name = "Jujutsu Sorcerer Style", Description = "Cursed energy dark fantasy sorcerer", PromptTemplate = "Transform the subject into a powerful jujutsu sorcerer. CRITICAL: Preserve the subject's exact facial features and identity. Render in MAPPA's Jujutsu Kaisen anime style — edgy dynamic character design with sharp features and intense eyes. Wearing the Tokyo Jujutsu High uniform — navy blue high-collar jacket and pants. Channeling cursed energy — dark purple and black swirling aura emanating from the body, geometric cursed technique patterns forming in the air. One hand extended performing a Domain Expansion hand seal. Background of a dark supernatural battlefield — cursed spirits as shadowy forms, shattered terrain, an eerie barrier forming as an inky void with floating cursed symbols. Dark moody color palette — midnight blue, purple, black, with electric blue highlights. Dark supernatural anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F441\uFE0F", AccentColor = "#311B92", IsActive = true, SortOrder = 104 },
            new StylePreset { Id = 345, Name = "Titan Scout Style", Description = "Elite Scout Regiment soldier dark anime", PromptTemplate = "Transform the subject into an elite Scout Regiment soldier from Attack on Titan. CRITICAL: Preserve the subject's exact facial features and identity. Render in semi-realistic anime style with intense dramatic expressions. Wearing the Survey Corps uniform — brown leather jacket with Wings of Freedom emblem on the back, white pants, knee-high brown boots. Equipped with Omni-Directional Mobility Gear — gas canisters, wire launchers, and dual ultra-hard steel blades drawn and ready. Dynamic mid-flight pose — soaring through the air with gear trailing wire cables, capes billowing. Background of a massive 50-meter Wall with colossal Titan fingers gripping the top, a Titan emerging from steam beyond. Muted military color palette — browns, greens, and grey with dramatic lighting. Dark epic anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F3F0", AccentColor = "#4E342E", IsActive = true, SortOrder = 105 },
            new StylePreset { Id = 346, Name = "Shinobi Ninja Style", Description = "Hidden Leaf Village ninja warrior anime", PromptTemplate = "Transform the subject into an elite shinobi ninja from the Hidden Leaf Village. CRITICAL: Preserve the subject's exact facial features and identity. Render in Naruto anime style — clean sharp character design with expressive eyes and dynamic poses. Wearing a ninja outfit — dark tactical vest over a black bodysuit. A Hidden Leaf Village forehead protector with the leaf symbol engraved in metal. Ninja tool pouch on the thigh. Performing a powerful jutsu — hands forming a ninjutsu hand sign, with swirling chakra energy around the body. A giant technique visible (Rasengan sphere, fire dragon, or shadow clones). Background of Konohagakure — the Hidden Leaf Village with Hokage Rock faces carved into the mountain. Orange, blue, and green ninja color palette. Naruto anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F365", AccentColor = "#FF6F00", IsActive = true, SortOrder = 106 },
            new StylePreset { Id = 347, Name = "Hero Academia Style", Description = "Quirk-powered superhero academy anime", PromptTemplate = "Transform the subject into a Pro Hero from the My Hero Academia universe. CRITICAL: Preserve the subject's exact facial features and identity. Render in MHA manga/anime style — dynamic expressive character design with detailed hero costumes. Wearing a unique custom-designed hero costume — bold color scheme, armored gauntlets, utility belt, cape or scarf, and a distinctive mask or visor. Activating their Quirk — dramatic power manifestation with visual effects (energy blasts, elemental control, physical transformation). Dynamic Plus Ultra action pose with determination. Background of U.A. High School campus or a city under villain attack. Bright bold manga color palette with action speed lines. My Hero Academia anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F4A5", AccentColor = "#1565C0", IsActive = true, SortOrder = 107 },
            new StylePreset { Id = 348, Name = "Devil Hunter Style", Description = "Chainsaw horror-action anime hunter", PromptTemplate = "Transform the subject into a Devil Hunter from Chainsaw Man. CRITICAL: Preserve the subject's exact facial features and identity. Render in MAPPA's gritty realistic anime style with raw visceral energy. Wearing a disheveled white shirt, loosened tie, and dark pants — battle-worn and splattered. Wild unkempt hair and intense exhausted yet determined eyes. A devil contract manifestation — chainsaw blades emerging from the arms and head, or a fiend transformation with devil horns and sharp teeth. Background of a dark Tokyo cityscape — demons emerging from shadows, destroyed city blocks, dramatic red sky. Dark gritty color palette — muted greys, blacks, with stark blood-red accents. Raw horror-action anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001FA9A", AccentColor = "#B71C1C", IsActive = true, SortOrder = 108 },
            new StylePreset { Id = 349, Name = "Shadow Monarch Style", Description = "S-Rank Hunter shadow army commander", PromptTemplate = "Transform the subject into an S-Rank Hunter and Shadow Monarch from Solo Leveling. CRITICAL: Preserve the subject's exact facial features and identity. Render in Solo Leveling anime style — sharp handsome character design with piercing glowing blue-violet eyes radiating power. Wearing a dark black hunter outfit — long dark coat over tactical gear. Dark purple and black shadow energy swirling around the body. Commanding an army of shadow soldiers — ghostly dark warriors with glowing purple eyes rising from dark portals on the ground. One hand extended commanding the shadows. Background of a massive dungeon gate — towering stone gate with red ominous glow. Dark black and deep purple color palette with neon blue-violet highlights. Solo Leveling anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F464", AccentColor = "#4A148C", IsActive = true, SortOrder = 109 },
            new StylePreset { Id = 350, Name = "Elden Ring Tarnished", Description = "Dark fantasy FromSoftware warrior", PromptTemplate = "Transform the subject into a Tarnished warrior from the Elden Ring dark fantasy world. CRITICAL: Preserve the subject's exact facial features and identity. Render in FromSoftware's dark fantasy aesthetic — weathered battle-scarred character with haunted determined eyes. Wearing ornate medieval Gothic plate armor with flowing tattered red cape, engravings and runes etched into the metal. Wielding a massive glowing rune-inscribed greatsword and a brass-trimmed shield. Grace site glowing faintly nearby. Background of the Lands Between — crumbling golden cathedral, vast desolate landscape with a massive golden glowing Erdtree in the distant sky, fog-shrouded ruins. Muted dark color palette — tarnished gold, deep crimson, fog grey. Dark fantasy video game art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F5E1\uFE0F", AccentColor = "#BF360C", IsActive = true, SortOrder = 110 },
            new StylePreset { Id = 351, Name = "Hyrule Champion Style", Description = "Legend of Zelda cel-shaded adventure", PromptTemplate = "Transform the subject into a Champion of Hyrule from The Legend of Zelda. CRITICAL: Preserve the subject's exact facial features and identity. Render in Nintendo's Breath of the Wild art style — soft cel-shaded anime-inspired character design with warm natural colors. Wearing the iconic blue Champion's Tunic with Sheikah patterns, brown traveler pants and boots, and a hooded cloak. Pointed elf-like ears. Wielding a glowing blue sacred sword and a sturdy shield. Paraglider strapped to the back. Background of the vast Hyrule landscape — rolling green hills, distant volcano, castle in the distance, ancient towers on the horizon. Cel-shaded watercolor quality with soft golden hour sunlight. Pastel blue, green, and gold color palette. Nintendo art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F9DD", AccentColor = "#2E7D32", IsActive = true, SortOrder = 111 },
            new StylePreset { Id = 352, Name = "Final Fantasy Crystal", Description = "Legendary JRPG high-fantasy warrior", PromptTemplate = "Transform the subject into a legendary warrior from the Final Fantasy universe. CRITICAL: Preserve the subject's exact facial features and identity. Render in iconic Final Fantasy character design — elegant elaborate costume with impossible fantasy fashion (zippers, belts, flowing asymmetric fabrics). Elaborate spiky or flowing hairstyle with silver streaks. Wielding an oversized ornate weapon — a massive sword, gunblade, or crystal staff. Dramatic battle-ready pose with magical aura. A crystal formation or magical rune circle glowing beneath. Background of a breathtaking landscape — floating islands, a crystal tower, airships in the sky, and waterfalls cascading into clouds. Luminous fantasy color palette — crystal blue, amethyst purple, and ethereal silver. Square Enix RPG character art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F48E", AccentColor = "#5C6BC0", IsActive = true, SortOrder = 112 },
            new StylePreset { Id = 353, Name = "Genshin Vision Style", Description = "Elemental Vision holder anime open world", PromptTemplate = "Transform the subject into an elemental Vision holder from the Genshin Impact universe. CRITICAL: Preserve the subject's exact facial features and identity. Render in HoYoverse's signature anime-meets-3D art style — beautiful polished character design with intricate costume details and soft cel-shaded coloring. Wearing an elaborate fantasy outfit inspired by a specific element — flowing fabrics, armor accents, elemental motifs (fire, ice, lightning, wind, water, nature, or stone). A glowing elemental Vision gem clipped to the outfit. Activating an Elemental Burst — dramatic elemental explosion with particles. Background of Teyvat — windmills, harbors, sakura trees, or rainforest. Vibrant anime color palette matching the element. Genshin Impact splash art quality.", Category = "Anime & Gaming", IconEmoji = "\u2728", AccentColor = "#00BFA5", IsActive = true, SortOrder = 113 },

            // ── K-Culture (14) ──
            new StylePreset { Id = 360, Name = "K-Drama Lead", Description = "Korean drama romantic lead character", PromptTemplate = "Transform the subject into a Korean drama lead character. CRITICAL: Preserve the subject's exact facial features and identity. Render with flawless glass-skin K-beauty complexion with soft dewy highlights. Styled with a trendy Korean hairstyle — perfectly tousled curtain bangs or sleek side-part. Wearing a stylish Korean fashion outfit — tailored coat over a turtleneck, or a chic business-casual ensemble. Soft romantic expression — gentle smile with warm sparkling eyes. Cinematic Korean drama lighting — golden hour warm tones with soft bokeh background. Background of an iconic K-drama setting — a rooftop overlooking Seoul skyline at sunset, cherry blossom-lined street, or a cozy cafe. Romantic atmospheric haze. Warm golden, blush pink, and soft cream color palette. Korean drama promotional poster quality.", Category = "K-Culture", IconEmoji = "\U0001F3AD", AccentColor = "#E91E63", IsActive = true, SortOrder = 120 },
            new StylePreset { Id = 361, Name = "K-Pop Idol Stage", Description = "K-Pop concert stage performance style", PromptTemplate = "Transform the subject into a K-Pop idol performing on stage. CRITICAL: Preserve the subject's exact facial features and identity. Render with striking K-Pop stage makeup — bold eye look with glitter, perfectly contoured features, and flawless porcelain skin. Show-stopping hairstyle — vibrant colored (platinum, pastel pink, or electric blue) perfectly styled hair. Wearing an avant-garde stage outfit — sequined jacket, leather harness, or futuristic concept costume with metallic accents. Dynamic dance performance pose — sharp powerful choreography frozen mid-move. Background of a massive concert stage — LED screens with abstract visuals, thousands of lightsticks glowing in the audience, confetti and pyrotechnic sparks. Electric purple, hot pink, and laser blue color palette. K-Pop music video quality.", Category = "K-Culture", IconEmoji = "\U0001F3A4", AccentColor = "#AA00FF", IsActive = true, SortOrder = 121 },
            new StylePreset { Id = 362, Name = "Webtoon Hero Style", Description = "Korean digital webtoon protagonist", PromptTemplate = "Transform the subject into a Korean webtoon protagonist. CRITICAL: Preserve the subject's exact facial features and identity. Render in the distinctive Korean digital webtoon art style — clean polished linework with soft gradient cel-shading and luminous coloring. Large expressive Korean-style eyes with detailed iris reflections. Trendy Korean character design — fashionable modern outfit, perfect proportions. Dramatic close-up portrait with sparkle and screen-tone effects. Manhwa-style speed lines for dramatic emphasis. Background transitioning from realistic Seoul cityscape to fantasy — magical portals, gaming interface overlays, or romantic cherry blossom petals. Soft pastel gradients with selective vivid color pops. Professional Korean webtoon serial art quality.", Category = "K-Culture", IconEmoji = "\U0001F4F1", AccentColor = "#2979FF", IsActive = true, SortOrder = 122 },
            new StylePreset { Id = 363, Name = "Korean Hanbok Portrait", Description = "Classical traditional Korean Hanbok attire", PromptTemplate = "Transform the subject into a classical Korean Hanbok portrait. CRITICAL: Preserve the subject's exact facial features and identity. Render wearing a magnificent traditional Korean Hanbok — a beautiful jeogori (upper garment) in rich vibrant silk with delicate gold embroidery and a flowing chima (skirt) in complementary color with ornate brocade patterns. Traditional Korean hair ornaments — a binyeo hairpin and daenggi ribbon in a classic updo, or a gat hat for men. Elegant refined posture with hands folded gracefully. Background of a beautiful Korean palace courtyard — Gyeongbokgung Palace with traditional wooden architecture, curved eaves, stone courtyard, and blooming chrysanthemums. Soft natural lighting. Rich hanbok colors — cerise pink, royal blue, jade green, and gold. Classical Korean portrait painting quality.", Category = "K-Culture", IconEmoji = "\U0001F458", AccentColor = "#AD1457", IsActive = true, SortOrder = 123 },
            new StylePreset { Id = 364, Name = "Seoul Neon Street", Description = "Neon-lit Gangnam/Hongdae night style", PromptTemplate = "Transform the subject into a stylish figure in neon-lit Seoul nightlife. CRITICAL: Preserve the subject's exact facial features and identity. Render with trendy Korean street fashion — oversized designer jacket, bucket hat or face mask pulled down, chunky sneakers, and layered accessories. Cool effortless confident pose — leaning against a wall or walking through a crosswalk. Background of iconic Seoul nightlife — Gangnam or Hongdae neon-lit streets with towering LED billboards showing K-Pop advertisements, glowing Korean Hangul signage, wet rain-reflective streets creating neon mirror effects. Street food stall steam rising. Dramatic neon lighting — electric pink, blue, and purple reflections on wet pavement. Urban night photography quality with cinematic color grading.", Category = "K-Culture", IconEmoji = "\U0001F303", AccentColor = "#6200EA", IsActive = true, SortOrder = 124 },
            new StylePreset { Id = 365, Name = "K-Beauty Editorial", Description = "Flawless Korean glass-skin beauty magazine", PromptTemplate = "Transform the subject into a K-Beauty editorial magazine cover. CRITICAL: Preserve the subject's exact facial features and identity. Render with the ultimate Korean glass-skin beauty aesthetic — luminous dewy porcelain skin with a lit-from-within glow. Perfect gradient lips in coral-to-pink. Soft puppy-eye or cat-eye makeup with shimmer eyeshadow. Naturally groomed fluffy brows. Flawless skin with visible dewdrop highlights on cheekbones and nose bridge. Hair styled with soft Korean waves. Minimal jewelry — delicate pearl earrings. Clean studio beauty lighting with soft ring-light catchlights in the eyes. Pure white or soft pastel gradient background with floating flower petals. Skin-tone, blush pink, and peach color palette. Korean beauty magazine editorial photography quality.", Category = "K-Culture", IconEmoji = "\U0001F484", AccentColor = "#F48FB1", IsActive = true, SortOrder = 125 },
            new StylePreset { Id = 366, Name = "Joseon Dynasty Portrait", Description = "Historical Korean royal court portrait", PromptTemplate = "Transform the subject into a Joseon Dynasty royal court portrait. CRITICAL: Preserve the subject's exact facial features and identity. Render in traditional Korean royal portrait style. Wearing elaborate Joseon royal court attire — a dragon-embroidered gonryongpo (royal robe) in deep crimson or blue with gold thread dragons and cloud motifs, an ikseongwan (winged cap) or hwagwan (flower crown). Formal seated royal pose on a throne with a folding screen behind. Rich brocade and silk textures with intricate embroidery details. Background of a Joseon royal court — painted irworobongdo screen behind the throne, wooden palace interior with latticed doors. Muted traditional Korean color palette — deep reds, indigo, gold, and cream. Classical Joseon Dynasty portrait painting quality.", Category = "K-Culture", IconEmoji = "\U0001F451", AccentColor = "#8D6E63", IsActive = true, SortOrder = 126 },
            new StylePreset { Id = 367, Name = "K-Pop Album Cover", Description = "Conceptual K-Pop album art photo", PromptTemplate = "Transform the subject into a conceptual K-Pop album cover photo. CRITICAL: Preserve the subject's exact facial features and identity. Render with high-concept K-Pop visual aesthetic — ethereal otherworldly styling with avant-garde fashion. Artistic editorial makeup with graphic elements — rhinestones, metallic accents, or painted designs on the face. Wearing a conceptual outfit — either dark moody (black leather, chains, dark romanticism) or dreamy ethereal (flowing white fabrics, angel wings, crystals). Artistic pose with strong visual composition. Background of a surreal K-Pop set — floating geometric shapes, holographic surfaces, otherworldly landscapes, or abstract color gradients. High-fashion editorial color grading. K-Pop album concept photo quality with magazine-level retouching.", Category = "K-Culture", IconEmoji = "\U0001F4BF", AccentColor = "#FF6D00", IsActive = true, SortOrder = 127 },
            new StylePreset { Id = 368, Name = "Korean Folklore", Description = "Mystical Korean mythology Gumiho spirit", PromptTemplate = "Transform the subject into a character from Korean folklore and mythology. CRITICAL: Preserve the subject's exact facial features and identity. Render as a mystical Gumiho (nine-tailed fox spirit) with ethereal fox ears, nine flowing fox tails made of blue-white spirit fire, and luminous golden eyes with vertical slit pupils. Wearing an elegant white and red traditional hanbok that flows and transforms into fox-fire at the edges. Holding a yeouiju (magical fox bead) glowing with blue mystical energy. Supernatural beauty with an enchanting yet dangerous expression. Background of a moonlit Korean mountain temple — ancient pine trees, stone pagodas, misty valleys, full moon casting silver light. Fox-fire wisps floating in the air. Blue-white, silver, and deep red color palette. Korean folklore meets modern fantasy illustration quality.", Category = "K-Culture", IconEmoji = "\U0001F98A", AccentColor = "#FF5722", IsActive = true, SortOrder = 128 },
            new StylePreset { Id = 369, Name = "Manhwa Action Style", Description = "Korean action manga protagonist", PromptTemplate = "Transform the subject into an action manhwa (Korean manga) protagonist. CRITICAL: Preserve the subject's exact facial features and identity. Render in dynamic Korean manhwa webtoon action style — sharp angular character design with intense determined eyes and sleek modern features. Dark hair with dramatic shading. Wearing a stylish modern combat outfit — tactical jacket, dark pants, combat boots with subtle magical or tech enhancements glowing. In the middle of an explosive action scene — delivering a powerful punch with shockwave impact rings. Dynamic speed lines and impact effects radiating outward. Background of an urban Seoul battlefield — cracked streets, shattered buildings, dungeon gate portals opening in the sky. High-contrast dramatic color palette — dark blacks with vivid red and electric blue highlights. Korean manhwa action art quality.", Category = "K-Culture", IconEmoji = "\u26A1", AccentColor = "#D50000", IsActive = true, SortOrder = 129 },
            new StylePreset { Id = 370, Name = "Korean Cafe Aesthetic", Description = "Cozy Seoul cafe lifestyle illustration", PromptTemplate = "Transform the subject into a cozy Korean cafe aesthetic scene. CRITICAL: Preserve the subject's exact facial features and identity. Render with warm soft Korean illustration style — gentle linework with watercolor-like pastel coloring. Wearing a comfortable chic outfit — oversized knit sweater, beret, or cozy scarf. Sitting in a Seoul cafe — holding a beautifully crafted latte art coffee cup, reading a book with a slice of Korean honey toast nearby. Soft content smile with warm eyes. Background of an aesthetic Korean cafe interior — exposed brick walls, warm Edison bulb string lights, wooden furniture, green hanging plants, floor-to-ceiling windows showing a rainy Seoul street. Warm cozy color palette — cream, caramel brown, sage green, and blush pink. Korean lifestyle illustration quality.", Category = "K-Culture", IconEmoji = "\u2615", AccentColor = "#795548", IsActive = true, SortOrder = 130 },
            new StylePreset { Id = 371, Name = "Chibi K-Pop", Description = "Adorable chibi K-Pop idol character", PromptTemplate = "Transform the subject into an adorable chibi K-Pop idol character. CRITICAL: Preserve the subject's facial likeness and identity in chibi form. Render in Korean chibi (SD — super deformed) style — enormous head (3:1 ratio to body), giant sparkly eyes with star-shaped highlights, tiny adorable body with stubby limbs. Cute K-Pop stage outfit miniaturized — sparkly jacket, lightstick accessory, and tiny headset microphone. Performing an iconic K-Pop heart pose — finger heart, double heart, or aegyo pose with blushing cheeks. Surrounded by cute floating elements — hearts, stars, music notes, sparkles, mini lightsticks. Background of pastel concert stage with chibi audience holding lightsticks. Pastel candy color palette — bubblegum pink, baby blue, lavender, and mint. Adorable Korean fan-art chibi illustration quality.", Category = "K-Culture", IconEmoji = "\U0001F9F8", AccentColor = "#EC407A", IsActive = true, SortOrder = 131 },
            new StylePreset { Id = 372, Name = "Korean Horror", Description = "Atmospheric Korean horror cinema style", PromptTemplate = "Transform the subject into a scene from Korean horror cinema. CRITICAL: Preserve the subject's exact facial features and identity. Render in atmospheric Korean horror film aesthetic — pale desaturated skin with dark shadows under the eyes, wet black hair partially covering the face. Wearing a simple white or school uniform outfit, dampened and slightly tattered. A subtle uncanny expression — wide unblinking eyes staring slightly off-center, ambiguous between fear and menace. A single hand reaching forward from darkness. Background of a dark rain-soaked apartment corridor with flickering fluorescent lights, or an abandoned school hallway with peeling wallpaper. Water stains creeping down walls. A ghostly reflection in a window. Desaturated cold color palette — pale blue-grey, sickly green, deep black with a single red accent. Korean horror film cinematography quality.", Category = "K-Culture", IconEmoji = "\U0001F47B", AccentColor = "#37474F", IsActive = true, SortOrder = 132 },
            new StylePreset { Id = 373, Name = "Korean Ink Brush", Description = "Traditional Korean sumi ink brush painting", PromptTemplate = "Transform the subject into a traditional Korean ink brush painting (sumukhwa). CRITICAL: Preserve the subject's facial likeness and identity. Render in elegant Korean sumi ink brush painting style — bold expressive black ink brushstrokes on textured hanji (Korean mulberry paper). Varying brush pressure creating thick-to-thin calligraphic lines — bold confident strokes for the main form with delicate thin strokes for details. Minimal color — primarily black ink with subtle washes of grey. A sparse touch of red cinnabar seal stamp in the corner. Negative space used masterfully — the empty paper as important as the painted areas. Background of natural Korean landscape elements — pine branches, bamboo, plum blossoms, or misty mountains in sansuhwa style. Monochrome ink with occasional pale blue-green or warm ochre wash accents. Traditional Korean literati painting quality.", Category = "K-Culture", IconEmoji = "\U0001F58C\uFE0F", AccentColor = "#263238", IsActive = true, SortOrder = 133 },

            // ── PhotoArts ──
            new StylePreset { Id = 434, Name = "Portrait Oil Painting", Description = "Expressive oil painting portrait on canvas", PromptTemplate = "A professional portrait of [subject] rendered as an expressive oil painting on canvas. High contrast, thick impasto brushwork in the background, and fine-detail blending on the face. Rich, warm color palette. The lighting should be dramatic, highlighting the contours of the face like a studio portrait. Artistic, painterly, textured, and sophisticated.", Category = "PhotoArts", IconEmoji = "\U0001F5BC\uFE0F", AccentColor = "#8D6E63", IsActive = true, SortOrder = 156 },
            new StylePreset { Id = 435, Name = "Smudge Oil Portrait", Description = "Ultra-smooth digital smudge painting with cinematic glow", PromptTemplate = "A high-quality digital oil painting of [subject]. The style is \"smudge painting\" with ultra-smooth skin textures, vibrant saturation, and visible but soft brushstrokes. The background is a soft-focus abstract bokeh with warm, moody lighting. Professional digital art, sharp facial features, deep shadows, and an artistic glow on the skin. 8k resolution, cinematic lighting.", Category = "PhotoArts", IconEmoji = "\U0001F3A8", AccentColor = "#E65100", IsActive = true, SortOrder = 157 },
            new StylePreset { Id = 436, Name = "Vexel Art Portrait", Description = "Clean vexel illustration with detailed hair and vibrant colors", PromptTemplate = "A stylized digital illustration of [subject]. Clean lines, smooth color gradients, and a \"vexel art\" aesthetic. The hair is highly detailed with individual light-catching strands. Simple, elegant, blurred background to make the subject pop. High-end retouching style, vibrant colors, and sharp, soulful eyes.", Category = "PhotoArts", IconEmoji = "\u2728", AccentColor = "#7C4DFF", IsActive = true, SortOrder = 158 }
        );
